{
  "name": "RunTrack Elite Pro",
  "description": "A professional running coaching platform connecting professors and students with advanced workout prescription and physical assessment tools."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Activity, Users, LogOut, CheckCircle2, Clock, 
  Target, Plus, Save, Trash2, X, ArrowRight, 
  Timer, AlertCircle, Sparkles, Phone, Lock, 
  ChevronDown, Dumbbell, Ruler, Scale, HeartPulse,
  Flame, Mountain, Zap, Repeat, LayoutDashboard,
  ClipboardList, Search, UserCheck
} from 'lucide-react';
import { initializeApp } from 'firebase/app';
import { 
  getFirestore, collection, doc, setDoc, 
  onSnapshot, addDoc, deleteDoc 
} from 'firebase/firestore';
import { 
  getAuth, signInAnonymously, onAuthStateChanged 
} from 'firebase/auth';

// --- CONFIGURAÇÃO FIREBASE ---
const firebaseConfig = JSON.parse(process.env.FIREBASE_CONFIG || '{}');
// Fallback for demo environment if env vars aren't present
const app = initializeApp(Object.keys(firebaseConfig).length ? firebaseConfig : { apiKey: "demo", projectId: "demo" });
const auth = getAuth(app);
const db = getFirestore(app);
const appId = 'runtrack-elite-v2'; // Namespace for this specific app version

// --- COMPONENTES DE UI ---

const Card = ({ children, className = "", onClick }: { children: React.ReactNode, className?: string, onClick?: () => void }) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-[2rem] shadow-sm border border-slate-100 p-8 transition-all ${onClick ? 'cursor-pointer hover:shadow-xl hover:-translate-y-1' : ''} ${className}`}
  >
    {children}
  </div>
);

const Button = ({ children, onClick, variant = "primary", className = "", loading = false, disabled = false }: any) => {
  const variants: any = {
    primary: "bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-500/20",
    secondary: "bg-slate-900 hover:bg-black text-white shadow-lg shadow-slate-500/20",
    success: "bg-emerald-600 hover:bg-emerald-700 text-white shadow-lg shadow-emerald-500/20",
    danger: "bg-rose-500 hover:bg-rose-600 text-white shadow-lg shadow-rose-500/20",
    ghost: "bg-transparent hover:bg-slate-100 text-slate-600",
    outline: "border-2 border-slate-200 text-slate-600 hover:bg-slate-50"
  };
  return (
    <button 
      onClick={onClick} 
      disabled={disabled || loading}
      className={`px-6 py-4 rounded-2xl font-black uppercase tracking-wide text-sm transition-all flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${variants[variant]} ${className}`}
    >
      {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : children}
    </button>
  );
};

const Input = ({ label, value, onChange, type = "text", placeholder, className = "" }: any) => (
  <div className="flex flex-col gap-2 w-full">
    {label && <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">{label}</label>}
    <input 
      type={type} value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder} 
      className={`px-5 py-4 rounded-2xl bg-slate-50 border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-900 placeholder:text-slate-300 w-full transition-all ${className}`} 
    />
  </div>
);

const Select = ({ label, value, onChange, options }: any) => (
  <div className="flex flex-col gap-2 w-full relative">
    {label && <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">{label}</label>}
    <div className="relative">
      <select 
        value={value} onChange={(e) => onChange(e.target.value)} 
        className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-none ring-1 ring-slate-200 focus:ring-2 focus:ring-blue-500 outline-none font-bold appearance-none cursor-pointer text-slate-900 pr-10"
      >
        {options.map((o: any) => <option key={o.value} value={o.value}>{o.label}</option>)}
      </select>
      <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400" size={18} />
    </div>
  </div>
);

const Badge = ({ children, color = "blue" }: { children: React.ReactNode, color?: string }) => {
    const colors: any = {
        blue: "bg-blue-50 text-blue-600 border-blue-100",
        rose: "bg-rose-50 text-rose-600 border-rose-100",
        emerald: "bg-emerald-50 text-emerald-600 border-emerald-100",
        amber: "bg-amber-50 text-amber-600 border-amber-100",
        purple: "bg-purple-50 text-purple-600 border-purple-100",
        orange: "bg-orange-50 text-orange-600 border-orange-100"
    }
    return (
        <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider border ${colors[color] || colors.blue}`}>
            {children}
        </span>
    )
}

// --- APP TYPES ---

type UserRole = 'professor' | 'student';

interface UserProfile {
  id: string;
  name: string;
  email?: string;
  phone: string; // Used for login
  role: UserRole;
  anamnesisComplete: boolean;
  // Bio Data
  age?: string;
  weight?: string;
  height?: string;
  bmi?: string;
  restingHeartRate?: string;
  injuries?: string;
  goal?: string;
}

interface WorkoutModel {
  id: string;
  studentId: string;
  type: 'longao' | 'fartlek' | 'tiro' | 'ritmo' | 'subida' | 'regenerativo';
  dayOfWeek: string; // Segunda, Terça...

  // Dynamic fields based on type
  warmupTime?: string;
  distance?: string; // km
  totalTime?: string; // min
  pace?: string; // min/km or zone

  // Intervals / Fartlek specific
  sets?: string;
  reps?: string;
  stimulusTime?: string; // min
  recoveryTime?: string; // sec or min

  // Fartlek specific
  fastTime?: string;
  slowTime?: string;

  description?: string;
  color?: string;
}

// --- MAIN COMPONENT ---

export default function App() {
  const [currentUser, setCurrentUser] = useState<any>(null); // Firebase Auth User
  const [activeProfile, setActiveProfile] = useState<UserProfile | null>(null); // App User Profile
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<'login' | 'student-select' | 'dashboard' | 'profile-setup'>('login');

  // Data State
  const [students, setStudents] = useState<UserProfile[]>([]);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  // Auth Init
  useEffect(() => {
    signInAnonymously(auth);
    onAuthStateChanged(auth, (u) => {
      setCurrentUser(u);
      setLoading(false);
    });
  }, []);

  // Fetch Students (Publicly readable for the login list)
  useEffect(() => {
    const unsub = onSnapshot(collection(db, 'artifacts', appId, 'users'), (snap) => {
      const allUsers = snap.docs.map(d => ({ id: d.id, ...d.data() } as UserProfile));
      setStudents(allUsers.filter(u => u.role === 'student'));
    });
    return () => unsub();
  }, []);

  // Login Handlers
  const loginAsProfessor = () => {
    setRole('professor');
    setView('dashboard');
  };

  const loginAsStudent = (profile: UserProfile) => {
    setActiveProfile(profile);
    setRole('student');
    setSelectedStudentId(profile.id);
    setView('dashboard');
  };

  // Render Logic
  if (loading) return <div className="h-screen w-full flex items-center justify-center bg-slate-50"><Activity className="animate-pulse text-blue-600" size={48} /></div>;

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      {/* Header (Visible if logged in or selecting student) */}
      {view !== 'login' && (
        <header className="fixed top-0 left-0 right-0 h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 z-50 px-6 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-blue-600 text-white p-2 rounded-xl shadow-lg shadow-blue-500/30">
                    <Activity size={20} />
                </div>
                <div>
                    <h1 className="text-lg font-black italic uppercase tracking-tighter leading-none">RunTrack <span className="text-blue-600">Pro</span></h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Performance System</p>
                </div>
            </div>

            <div className="flex items-center gap-4">
                {role === 'professor' && selectedStudentId && (
                   <div className="hidden md:flex items-center gap-2 px-4 py-2 bg-blue-50 rounded-full border border-blue-100">
                      <UserCheck size={14} className="text-blue-600"/>
                      <span className="text-xs font-bold text-blue-700 uppercase">Editando: {students.find(s => s.id === selectedStudentId)?.name}</span>
                   </div> 
                )}
                <button onClick={() => { setView('login'); setRole(null); setActiveProfile(null); setSelectedStudentId(null); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-rose-500 transition-colors">
                    <LogOut size={20} />
                </button>
            </div>
        </header>
      )}

      {/* Main Content Area */}
      <main className={`transition-all duration-500 ${view !== 'login' ? 'pt-28 pb-12 px-6' : ''}`}>

        {view === 'login' && (
          <LoginScreen 
            onSelectProfessor={loginAsProfessor} 
            onSelectStudent={() => setView('student-select')} 
          />
        )}

        {view === 'student-select' && (
          <StudentLoginList 
            students={students} 
            onLogin={loginAsStudent} 
            onBack={() => setView('login')} 
          />
        )}

        {view === 'dashboard' && role === 'professor' && (
            <ProfessorDashboard 
                students={students} 
                selectedStudentId={selectedStudentId}
                onSelectStudent={setSelectedStudentId}
            />
        )}

        {view === 'dashboard' && role === 'student' && activeProfile && (
             <StudentView profile={activeProfile} />
        )}

      </main>
    </div>
  );
}

// --- SUB-SCREENS ---

function LoginScreen({ onSelectProfessor, onSelectStudent }: any) {
    return (
        <div className="h-screen flex flex-col items-center justify-center p-6 relative overflow-hidden">
            {/* Background Decor */}
            <div className="absolute top-[-10%] left-[-10%] w-[50vh] h-[50vh] bg-blue-400/20 rounded-full blur-[100px] pointer-events-none" />
            <div className="absolute bottom-[-10%] right-[-10%] w-[50vh] h-[50vh] bg-indigo-400/20 rounded-full blur-[100px] pointer-events-none" />

            <div className="text-center mb-16 relative z-10">
                <div className="bg-white p-4 rounded-[2rem] shadow-xl inline-block mb-6 animate-bounce">
                    <Activity className="text-blue-600 w-16 h-16" />
                </div>
                <h1 className="text-6xl font-black italic uppercase tracking-tighter text-slate-900 mb-4">
                    RunTrack <span className="text-blue-600">Elite</span>
                </h1>
                <p className="text-slate-500 uppercase tracking-[0.5em] text-xs font-bold">
                    Plataforma de Alta Performance
                </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full relative z-10">
                <Card 
                    onClick={onSelectProfessor} 
                    className="group border-b-8 border-b-slate-100 hover:border-b-blue-600 transition-all active:scale-95"
                >
                    <div className="h-40 flex flex-col items-center justify-center gap-6">
                        <div className="bg-blue-50 text-blue-600 p-5 rounded-3xl group-hover:scale-110 transition-transform">
                            <LayoutDashboard size={40} />
                        </div>
                        <h2 className="text-2xl font-black uppercase italic tracking-tight">Sou Professor</h2>
                    </div>
                </Card>

                <Card 
                    onClick={onSelectStudent} 
                    className="group border-b-8 border-b-slate-100 hover:border-b-emerald-500 transition-all active:scale-95"
                >
                    <div className="h-40 flex flex-col items-center justify-center gap-6">
                        <div className="bg-emerald-50 text-emerald-600 p-5 rounded-3xl group-hover:scale-110 transition-transform">
                            <Users size={40} />
                        </div>
                        <h2 className="text-2xl font-black uppercase italic tracking-tight">Sou Aluno</h2>
                    </div>
                </Card>
            </div>
        </div>
    )
}

function StudentLoginList({ students, onLogin, onBack }: { students: UserProfile[], onLogin: (p: UserProfile) => void, onBack: () => void }) {
    const [searchTerm, setSearchTerm] = useState("");
    const [selectedForAuth, setSelectedForAuth] = useState<UserProfile | null>(null);
    const [phoneInput, setPhoneInput] = useState("");
    const [error, setError] = useState("");

    const filtered = students.filter(s => s.name.toLowerCase().includes(searchTerm.toLowerCase()));

    const handleAuth = () => {
        if (!selectedForAuth) return;
        // Simple phone check - remove non-digits for comparison
        const storedPhone = selectedForAuth.phone.replace(/\D/g, '');
        const inputPhone = phoneInput.replace(/\D/g, '');

        if (storedPhone === inputPhone && inputPhone.length > 5) {
            onLogin(selectedForAuth);
        } else {
            setError("Número de celular incorreto.");
        }
    }

    return (
        <div className="max-w-2xl mx-auto pt-10">
            <div className="flex items-center gap-4 mb-8">
                <button onClick={onBack} className="p-3 bg-white rounded-full shadow-sm hover:shadow-md transition-all text-slate-400 hover:text-slate-800">
                    <ArrowRight className="rotate-180" size={20} />
                </button>
                <h2 className="text-3xl font-black uppercase italic tracking-tighter">Selecione seu Perfil</h2>
            </div>

            <div className="relative mb-8">
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input 
                    type="text" 
                    placeholder="Buscar atleta..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-14 pr-6 py-5 rounded-[2rem] bg-white border border-slate-200 focus:ring-4 focus:ring-blue-100 outline-none font-bold text-lg"
                />
            </div>

            <div className="grid gap-4">
                {filtered.map(student => (
                    <Card key={student.id} onClick={() => { setSelectedForAuth(student); setError(""); setPhoneInput(""); }} className="flex items-center justify-between p-6 hover:ring-2 hover:ring-blue-500/20">
                        <div className="flex items-center gap-4">
                            <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-500 font-black text-xl">
                                {student.name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-bold text-lg text-slate-900 leading-tight">{student.name}</h3>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Atleta</p>
                            </div>
                        </div>
                        <div className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-slate-300">
                            <ArrowRight size={20} />
                        </div>
                    </Card>
                ))}
                {filtered.length === 0 && (
                    <div className="text-center py-20 text-slate-400 font-bold">Nenhum atleta encontrado.</div>
                )}
            </div>

            {/* Auth Modal */}
            {selectedForAuth && (
                <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
                    <Card className="max-w-md w-full animate-in zoom-in-95 duration-200">
                        <div className="flex justify-between items-start mb-6">
                            <div>
                                <h3 className="text-2xl font-black italic uppercase tracking-tight text-slate-900">Acesso Seguro</h3>
                                <p className="text-slate-500 text-sm mt-1">Confirme seu número para entrar.</p>
                            </div>
                            <button onClick={() => setSelectedForAuth(null)} className="text-slate-300 hover:text-slate-600"><X /></button>
                        </div>

                        <div className="bg-blue-50 p-4 rounded-2xl mb-6 flex items-center gap-4">
                            <div className="w-10 h-10 bg-blue-200 rounded-full flex items-center justify-center text-blue-700 font-bold">
                                {selectedForAuth.name.charAt(0)}
                            </div>
                            <span className="font-bold text-blue-900">{selectedForAuth.name}</span>
                        </div>

                        <div className="space-y-4">
                            <Input 
                                label="Celular Cadastrado" 
                                placeholder="Ex: 11999999999" 
                                value={phoneInput} 
                                onChange={setPhoneInput} 
                                type="tel"
                            />
                            {error && <p className="text-rose-500 text-xs font-bold flex items-center gap-2"><AlertCircle size={14}/> {error}</p>}
                            <Button onClick={handleAuth} className="w-full py-5 text-lg">Confirmar Acesso</Button>
                        </div>
                    </Card>
                </div>
            )}
        </div>
    )
}

// --- PROFESSOR DASHBOARD & WORKFLOW ---

function ProfessorDashboard({ students, selectedStudentId, onSelectStudent }: any) {
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [newStudent, setNewStudent] = useState({ name: '', phone: '' });

    // Create new student
    const handleAddStudent = async () => {
        if (!newStudent.name || !newStudent.phone) return;
        try {
            const id = doc(collection(db, 'temp')).id; // generate ID
            const payload: UserProfile = {
                id,
                name: newStudent.name,
                phone: newStudent.phone,
                role: 'student',
                anamnesisComplete: false
            };
            await setDoc(doc(db, 'artifacts', appId, 'users', id), payload);
            setIsAddModalOpen(false);
            setNewStudent({ name: '', phone: '' });
        } catch (e) {
            console.error(e);
        }
    };

    // If a student is selected, show their workspace
    if (selectedStudentId) {
        const student = students.find((s: UserProfile) => s.id === selectedStudentId);
        if (!student) return <div>Erro ao carregar aluno.</div>;

        return (
            <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <button onClick={() => onSelectStudent(null)} className="flex items-center gap-2 text-slate-400 hover:text-blue-600 transition-colors font-bold uppercase text-xs tracking-widest mb-4">
                    <ArrowRight className="rotate-180" size={16} /> Voltar para Lista
                </button>

                <div className="flex flex-col md:flex-row gap-8">
                    {/* Left: Profile & Assessment */}
                    <div className="w-full md:w-1/3 space-y-6">
                        <StudentProfileCard student={student} />
                    </div>

                    {/* Right: Workouts */}
                    <div className="w-full md:w-2/3">
                        <WorkoutManager student={student} />
                    </div>
                </div>
            </div>
        );
    }

    // List View
    return (
        <div className="max-w-6xl mx-auto">
            <div className="flex justify-between items-end mb-12 border-b border-slate-200 pb-6">
                <div>
                    <h2 className="text-4xl font-black italic uppercase tracking-tighter text-slate-900">Meus Atletas</h2>
                    <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-2">Gestão de Squad</p>
                </div>
                <Button onClick={() => setIsAddModalOpen(true)} className="shadow-xl">
                    <Plus size={20} /> Novo Atleta
                </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {students.map((s: UserProfile) => (
                    <Card key={s.id} onClick={() => onSelectStudent(s.id)} className="group cursor-pointer hover:border-blue-500/30">
                        <div className="flex items-center justify-between mb-6">
                            <div className="w-16 h-16 bg-gradient-to-br from-slate-100 to-slate-200 rounded-2xl flex items-center justify-center text-slate-600 font-black text-2xl shadow-inner">
                                {s.name.charAt(0)}
                            </div>
                            <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wide ${s.anamnesisComplete ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                                {s.anamnesisComplete ? 'Ativo' : 'Pendente'}
                            </div>
                        </div>
                        <h3 className="text-xl font-black uppercase italic text-slate-800 truncate">{s.name}</h3>
                        <p className="text-xs font-bold text-slate-400 mt-1 flex items-center gap-2"><Phone size={12}/> {s.phone}</p>

                        <div className="mt-8 pt-6 border-t border-slate-50 flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity">
                            <span className="text-xs font-bold text-blue-600 uppercase">Gerenciar</span>
                            <ArrowRight size={16} className="text-blue-600" />
                        </div>
                    </Card>
                ))}
            </div>

            {isAddModalOpen && (
                <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
                    <Card className="max-w-md w-full">
                        <div className="flex justify-between mb-6"><h3 className="text-xl font-black italic uppercase">Cadastrar Atleta</h3><button onClick={() => setIsAddModalOpen(false)}><X /></button></div>
                        <div className="space-y-4">
                            <Input label="Nome Completo" value={newStudent.name} onChange={(v: string) => setNewStudent({...newStudent, name: v})} placeholder="Ex: João Silva" />
                            <Input label="Celular (Login)" value={newStudent.phone} onChange={(v: string) => setNewStudent({...newStudent, phone: v})} placeholder="Ex: 11999999999" type="tel" />
                            <Button onClick={handleAddStudent} className="w-full mt-4">Criar Perfil</Button>
                        </div>
                    </Card>
                </div>
            )}
        </div>
    );
}

function StudentProfileCard({ student }: { student: UserProfile }) {
    const [isEditing, setIsEditing] = useState(false);
    const [data, setData] = useState(student);
    const [saving, setSaving] = useState(false);

    const handleSave = async () => {
        setSaving(true);
        const updated = { ...data, anamnesisComplete: true };
        await setDoc(doc(db, 'artifacts', appId, 'users', student.id), updated, { merge: true });
        setSaving(false);
        setIsEditing(false);
    };

    if (isEditing) {
        return (
            <Card className="border-l-4 border-l-blue-500 h-full">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black italic uppercase text-lg">Avaliação & Anamnese</h3>
                    <button onClick={() => setIsEditing(false)}><X size={20} className="text-slate-400"/></button>
                </div>
                <div className="space-y-4 max-h-[600px] overflow-y-auto pr-2">
                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                        <h4 className="text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest flex items-center gap-2"><Scale size={12}/> Biometria</h4>
                        <div className="grid grid-cols-2 gap-3">
                            <Input label="Idade" type="number" value={data.age || ''} onChange={(v: string) => setData({...data, age: v})} />
                            <Input label="Peso (kg)" type="number" value={data.weight || ''} onChange={(v: string) => setData({...data, weight: v})} />
                            <Input label="Altura (cm)" type="number" value={data.height || ''} onChange={(v: string) => setData({...data, height: v})} />
                            <Input label="FC Repouso" type="number" value={data.restingHeartRate || ''} onChange={(v: string) => setData({...data, restingHeartRate: v})} />
                        </div>
                    </div>

                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                        <h4 className="text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest flex items-center gap-2"><ClipboardList size={12}/> Histórico</h4>
                        <div className="space-y-3">
                            <Select label="Objetivo Principal" value={data.goal || 'condition'} onChange={(v: string) => setData({...data, goal: v})} options={[
                                {value: 'condition', label: 'Condicionamento Geral'},
