        longao: 'bg-indigo-600',
        tiro: 'bg-rose-500',
        fartlek: 'bg-purple-600',
        ritmo: 'bg-orange-500',
        subida: 'bg-amber-600',
        regenerativo: 'bg-emerald-500'
    };

    const bgColor = colorMap[workout.type] || 'bg-slate-500';

    return (
        <Card className="relative overflow-hidden group border-none ring-1 ring-slate-100 shadow-lg">
            <div className={`absolute top-0 left-0 w-2 h-full ${bgColor}`} />

            <div className="flex justify-between items-start pl-4">
                <div>
                    <div className="flex items-center gap-3 mb-2">
                         <Badge>{workout.dayOfWeek}</Badge>
                         <span className="text-[10px] font-black uppercase tracking-widest text-slate-300">{workout.totalTime} MIN TOTAIS</span>
                    </div>
                    <h4 className="text-2xl font-black italic uppercase tracking-tighter text-slate-800">{workout.type}</h4>

                    <div className="mt-4 text-sm text-slate-600 font-medium leading-relaxed max-w-md">
                        {workout.type === 'tiro' || workout.type === 'subida' ? (
                            <span>{workout.warmupTime}' Aquec. + <strong>{workout.sets}x ({workout.reps} estímulos de {workout.stimulusTime} / {workout.recoveryTime} rec)</strong> + {workout.cooldownTime}' Final.</span>
                        ) : workout.type === 'fartlek' ? (
                            <span>{workout.warmupTime}' Aquec + Alternar <strong>{workout.fastTime}' Forte / {workout.slowTime}' Leve</strong> até completar {workout.totalTime} min.</span>
                        ) : (
                            <span>Volume total de <strong>{workout.distance}km</strong>. Pace alvo: {workout.pace || 'Livre'}.</span>
                        )}
                    </div>

                    {workout.description && <p className="mt-2 text-xs italic text-slate-400">Obs: {workout.description}</p>}
                </div>

                <div className="flex flex-col items-end gap-2">
