            <div className="absolute bottom-[-10%] right-[-10%] w-[50vh] h-[50vh] bg-indigo-400/20 rounded-full blur-[100px] pointer-events-none" />

            <div className="text-center mb-16 relative z-10">
                <div className="bg-white p-4 rounded-[2rem] shadow-xl inline-block mb-6 animate-bounce">
                    <Activity className="text-blue-600 w-16 h-16" />
                </div>
                <h1 className="text-6xl font-black italic uppercase tracking-tighter text-slate-900 mb-4">
                    RunTrack <span className="text-blue-600">Elite</span>
                </h1>
                <p className="text-slate-500 uppercase tracking-[0.5em] text-xs font-bold">
