                    <div className="h-40 flex flex-col items-center justify-center gap-6">
                        <div className="bg-blue-50 text-blue-600 p-5 rounded-3xl group-hover:scale-110 transition-transform">
                            <LayoutDashboard size={40} />
                        </div>
                        <h2 className="text-2xl font-black uppercase italic tracking-tight">Sou Professor</h2>
