function WorkoutManager({ student }: { student: UserProfile }) {
    const [workouts, setWorkouts] = useState<WorkoutModel[]>([]);
    const [isCreating, setIsCreating] = useState(false);

    useEffect(() => {
        const q = collection(db, 'artifacts', appId, 'workouts');
        const unsub = onSnapshot(q, (snap) => {
            const data = snap.docs.map(d => ({id: d.id, ...d.data()} as WorkoutModel));
            setWorkouts(data.filter(w => w.studentId === student.id));
        });
        return () => unsub();
    }, [student.id]);

    const deleteWorkout = async (id: string) => {
        if(confirm("Tem certeza que deseja excluir este treino?")) {
            await deleteDoc(doc(db, 'artifacts', appId, 'workouts', id));
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100">
                <h3 className="text-xl font-black italic uppercase tracking-tighter flex items-center gap-3">
                    <Flame className="text-orange-500" /> Prescrição de Treinos
                </h3>
                <Button onClick={() => setIsCreating(true)} variant="secondary" className="px-8">
                   <Plus size={18} /> Novo Treino
                </Button>
            </div>

            {isCreating && (
                <WorkoutBuilder 
                    studentId={student.id} 
                    onClose={() => setIsCreating(false)} 
                />
            )}

            <div className="grid gap-4">
                {workouts.length === 0 ? (
                    <div className="text-center py-12 text-slate-400 bg-white rounded-[2rem] border border-slate-100 border-dashed">
                        <p className="font-bold">Nenhum treino prescrito.</p>
                    </div>
                ) : (
                   workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek)).map(w => (
                       <WorkoutCard key={w.id} workout={w} onDelete={() => deleteWorkout(w.id)} />
                   )) 
                )}
            </div>
        </div>
    )
}

function WorkoutBuilder({ studentId, onClose }: { studentId: string, onClose: () => void }) {
    const [type, setType] = useState<WorkoutModel['type']>('longao');
    const [day, setDay] = useState('Segunda');
    const [loading, setLoading] = useState(false);

    // Form States
    const [common, setCommon] = useState({ distance: '', time: '', pace: '', description: '', warmup: '10', cooldown: '5' });
    const [interval, setInterval] = useState({ sets: '1', reps: '10', stim: '2', rec: '1', recType: 'min' });
    const [fartlek, setFartlek] = useState({ fast: '1', slow: '1' });

    const handleSave = async () => {
        setLoading(true);
        try {
            const payload: any = {
                studentId,
                type,
                dayOfWeek: day,
                warmupTime: common.warmup,
                cooldownTime: common.cooldown,
                description: common.description,
                createdAt: new Date().toISOString()
            };

            // Calculate total time approximate based on inputs
            let estimatedTotal = 0;
            const w = Number(common.warmup) || 0;
            const c = Number(common.cooldown) || 0;

            if (type === 'longao' || type === 'ritmo' || type === 'regenerativo') {
                payload.distance = common.distance;
                payload.pace = common.pace;
                payload.totalTime = common.time; 
            } else if (type === 'tiro' || type === 'subida') {
                payload.sets = interval.sets;
                payload.reps = interval.reps;
                payload.stimulusTime = interval.stim;
                payload.recoveryTime = interval.rec;

                const sets = Number(interval.sets) || 1;
                const reps = Number(interval.reps) || 1;
                const stim = Number(interval.stim) || 0;
                const rec = Number(interval.rec) || 0;
                estimatedTotal = w + c + (sets * (reps * (stim + rec)));
                payload.totalTime = String(estimatedTotal);
            } else if (type === 'fartlek') {
                payload.totalTime = common.time;
                payload.fastTime = fartlek.fast;
                payload.slowTime = fartlek.slow;
            }

            await addDoc(collection(db, 'artifacts', appId, 'workouts'), payload);
            onClose();
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    return (
        <Card className="border-2 border-blue-600 bg-slate-50 relative animate-in zoom-in-95 duration-200">
            <button onClick={onClose} className="absolute top-4 right-4 text-slate-400 hover:text-slate-800"><X /></button>
            <h4 className="text-lg font-black italic uppercase mb-6 text-blue-700">Montar Sessão de Treino</h4>

            <div className="grid grid-cols-2 gap-4 mb-6">
                <Select label="Dia da Semana" value={day} onChange={setDay} options={[
                    {value: 'Segunda', label: 'Segunda-feira'},
                    {value: 'Terça', label: 'Terça-feira'},
                    {value: 'Quarta', label: 'Quarta-feira'},
                    {value: 'Quinta', label: 'Quinta-feira'},
                    {value: 'Sexta', label: 'Sexta-feira'},
                    {value: 'Sábado', label: 'Sábado'},
                    {value: 'Domingo', label: 'Domingo'}
                ]} />
                <Select label="Método" value={type} onChange={setType} options={[
                    {value: 'longao', label: 'Longão (Volume)'},
                    {value: 'tiro', label: 'Intervalado (Tiros)'},
                    {value: 'fartlek', label: 'Fartlek (Variado)'},
                    {value: 'ritmo', label: 'Tempo Run (Ritmo)'},
                    {value: 'subida', label: 'Força (Subidas)'},
                    {value: 'regenerativo', label: 'Regenerativo (Leve)'}
                ]} />
            </div>

            <div className="bg-white p-6 rounded-2xl border border-slate-200 mb-6 space-y-4">
                {/* Dynamic Fields */}
                {(type === 'longao' || type === 'ritmo' || type === 'regenerativo') && (
                    <div className="grid grid-cols-2 gap-4">
                        <Input label="Distância (km)" type="number" value={common.distance} onChange={(v: string) => setCommon({...common, distance: v})} />
                        <Input label="Tempo Total (min)" type="number" value={common.time} onChange={(v: string) => setCommon({...common, time: v})} />
                        <Input label="Pace Alvo (min/km)" value={common.pace} onChange={(v: string) => setCommon({...common, pace: v})} className="col-span-2" />
                    </div>
                )}

                {(type === 'tiro' || type === 'subida') && (
                    <div className="space-y-4">
                        <div className="grid grid-cols-3 gap-4">
                            <Input label="Aquecimento (min)" type="number" value={common.warmup} onChange={(v: string) => setCommon({...common, warmup: v})} />
                            <Input label="Desaquecimento" type="number" value={common.cooldown} onChange={(v: string) => setCommon({...common, cooldown: v})} />
                            <Input label="Séries (Blocos)" type="number" value={interval.sets} onChange={(v: string) => setInterval({...interval, sets: v})} />
                        </div>
                        <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 grid grid-cols-3 gap-4">
                            <Input label="Repetições" type="number" value={interval.reps} onChange={(v: string) => setInterval({...interval, reps: v})} />
                            <Input label="Estímulo (min/dist)" value={interval.stim} onChange={(v: string) => setInterval({...interval, stim: v})} />
                            <Input label="Recuperação (min)" value={interval.rec} onChange={(v: string) => setInterval({...interval, rec: v})} />
                        </div>
                    </div>
                )}

                {type === 'fartlek' && (
                    <div className="space-y-4">
                         <div className="grid grid-cols-2 gap-4">
                            <Input label="Tempo Total (min)" type="number" value={common.time} onChange={(v: string) => setCommon({...common, time: v})} />
                            <Input label="Aquecimento (min)" type="number" value={common.warmup} onChange={(v: string) => setCommon({...common, warmup: v})} />
                         </div>
                         <div className="p-4 bg-purple-50 rounded-xl border border-purple-100 grid grid-cols-2 gap-4">
                            <Input label="Forte (min)" type="number" value={fartlek.fast} onChange={(v: string) => setFartlek({...fartlek, fast: v})} />
                            <Input label="Fraco (min)" type="number" value={fartlek.slow} onChange={(v: string) => setFartlek({...fartlek, slow: v})} />
                         </div>
                    </div>
                )}

                <TextArea label="Observações Técnicas" value={common.description} onChange={(v: string) => setCommon({...common, description: v})} placeholder="Ex: Terreno plano, focar na postura..." />
            </div>

            <Button onClick={handleSave} loading={loading} className="w-full text-lg">Confirmar Prescrição</Button>
        </Card>
    );
}

