function StudentLoginList({ students, onLogin, onBack }: { students: UserProfile[], onLogin: (p: UserProfile) => void, onBack: () => void }) {
    const [searchTerm, setSearchTerm] = useState("");
    const [selectedForAuth, setSelectedForAuth] = useState<UserProfile | null>(null);
    const [phoneInput, setPhoneInput] = useState("");
    const [error, setError] = useState("");

    const filtered = students.filter(s => s.name.toLowerCase().includes(searchTerm.toLowerCase()));

    const handleAuth = () => {
        if (!selectedForAuth) return;
        const storedPhone = selectedForAuth.phone.replace(/\D/g, '');
        const inputPhone = phoneInput.replace(/\D/g, '');

        if (storedPhone === inputPhone && inputPhone.length > 5) {
            onLogin(selectedForAuth);
        } else {
            setError("Número de celular incorreto.");
        }
    }

    return (
        <div className="max-w-2xl mx-auto pt-10">
            <div className="flex items-center gap-4 mb-8">
                <button onClick={onBack} className="p-3 bg-white rounded-full shadow-sm hover:shadow-md transition-all text-slate-400 hover:text-slate-800">
                    <ArrowRight className="rotate-180" size={20} />
                </button>
                <h2 className="text-3xl font-black uppercase italic tracking-tighter">Selecione seu Perfil</h2>
            </div>

            <div className="relative mb-8">
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input 
                    type="text" 
                    placeholder="Buscar atleta..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-14 pr-6 py-5 rounded-[2rem] bg-white border border-slate-200 focus:ring-4 focus:ring-blue-100 outline-none font-bold text-lg"
                />
            </div>

            <div className="grid gap-4">
                {filtered.map(student => (
                    <Card key={student.id} onClick={() => { setSelectedForAuth(student); setError(""); setPhoneInput(""); }} className="flex items-center justify-between p-6 hover:ring-2 hover:ring-blue-500/20">
                        <div className="flex items-center gap-4">
                            <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-500 font-black text-xl">
                                {student.name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-bold text-lg text-slate-900 leading-tight">{student.name}</h3>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Atleta</p>
                            </div>
                        </div>
                        <div className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-slate-300">
                            <ArrowRight size={20} />
                        </div>
                    </Card>
                ))}
            </div>

            {selectedForAuth && (
                <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
                    <Card className="max-w-md w-full animate-in zoom-in-95 duration-200">
                        <div className="flex justify-between items-start mb-6">
                            <div>
                                <h3 className="text-2xl font-black italic uppercase tracking-tight text-slate-900">Acesso Seguro</h3>
                                <p className="text-slate-500 text-sm mt-1">Confirme seu número para entrar.</p>
                            </div>
                            <button onClick={() => setSelectedForAuth(null)} className="text-slate-300 hover:text-slate-600"><X /></button>
