export default function App() {
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [activeProfile, setActiveProfile] = useState<UserProfile | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<'login' | 'student-select' | 'dashboard' | 'profile-setup'>('login');

  // Data State
  const [students, setStudents] = useState<UserProfile[]>([]);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  // Auth Init
  useEffect(() => {
    // Check if running in demo mode to bypass auth errors
    if (app.options.apiKey === 'demo') {
      setCurrentUser({ uid: 'demo-user', isAnonymous: true });
      setLoading(false);
      return;
    }

    // Try signing in anonymously
    signInAnonymously(auth).catch((error) => {
      console.error("Auth failed:", error);
      // Even if auth fails, we set a fallback user so the UI can render
      // This handles cases where API Key is invalid but we still want to show the app structure
      setCurrentUser({ uid: 'fallback-user', isAnonymous: true });
      setLoading(false);
    });

    const unsubscribe = onAuthStateChanged(auth, (u) => {
      if (u) {
        setCurrentUser(u);
        setLoading(false);
      }
    });

    return () => unsubscribe();
  }, []);

  // Fetch Students
  useEffect(() => {
    // Add error handling for snapshot to prevent crash on invalid config
    try {
      const unsub = onSnapshot(collection(db, 'artifacts', appId, 'users'), (snap) => {
        const allUsers = snap.docs.map(d => ({ id: d.id, ...d.data() } as UserProfile));
        setStudents(allUsers.filter(u => u.role === 'student'));
      }, (error) => {
        console.error("Firestore Error:", error);
        // Optional: Set empty students or handle offline mode
      });
      return () => unsub();
    } catch (e) {
      console.error("Firestore Init Error:", e);
    }
  }, []);

  // Login Handlers
  const loginAsProfessor = () => {
    setRole('professor');
    setView('dashboard');
  };

  const loginAsStudent = (profile: UserProfile) => {
    setActiveProfile(profile);
    setRole('student');
    setSelectedStudentId(profile.id);
    setView('dashboard');
  };

  if (loading) return <div className="h-screen w-full flex items-center justify-center bg-slate-50"><Activity className="animate-pulse text-blue-600" size={48} /></div>;

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      {/* Header */}
      {view !== 'login' && (
        <header className="fixed top-0 left-0 right-0 h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 z-50 px-6 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="bg-blue-600 text-white p-2 rounded-xl shadow-lg shadow-blue-500/30">
                    <Activity size={20} />
                </div>
                <div>
                    <h1 className="text-lg font-black italic uppercase tracking-tighter leading-none">RunTrack <span className="text-blue-600">Pro</span></h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Performance System</p>
                </div>
            </div>

            <div className="flex items-center gap-4">
                {role === 'professor' && selectedStudentId && (
                   <div className="hidden md:flex items-center gap-2 px-4 py-2 bg-blue-50 rounded-full border border-blue-100">
                      <UserCheck size={14} className="text-blue-600"/>
                      <span className="text-xs font-bold text-blue-700 uppercase">Editando: {students.find(s => s.id === selectedStudentId)?.name}</span>
                   </div> 
                )}
                <button onClick={() => { setView('login'); setRole(null); setActiveProfile(null); setSelectedStudentId(null); }} className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-rose-500 transition-colors">
                    <LogOut size={20} />
                </button>
            </div>
        </header>
      )}

      {/* Main Content */}
      <main className={`transition-all duration-500 ${view !== 'login' ? 'pt-28 pb-12 px-6' : ''}`}>

        {view === 'login' && (
          <LoginScreen 
            onSelectProfessor={loginAsProfessor} 
            onSelectStudent={() => setView('student-select')} 
          />
        )}

        {view === 'student-select' && (
          <StudentLoginList 
            students={students} 
            onLogin={loginAsStudent} 
            onBack={() => setView('login')} 
          />
        )}

        {view === 'dashboard' && role === 'professor' && (
            <ProfessorDashboard 
                students={students} 
                selectedStudentId={selectedStudentId}
                onSelectStudent={setSelectedStudentId}
            />
        )}

        {view === 'dashboard' && role === 'student' && activeProfile && (
             <StudentView profile={activeProfile} />
        )}

      </main>
    </div>
  );
}

