function ProfessorDashboard({ students, selectedStudentId, onSelectStudent }: any) {
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [newStudent, setNewStudent] = useState({ name: '', phone: '' });
    const [createLoading, setCreateLoading] = useState(false);
    const [createError, setCreateError] = useState('');

    // Robust Add Student Logic
    const handleAddStudent = async () => {
        if (!newStudent.name || !newStudent.phone) {
            setCreateError('Por favor, preencha todos os campos.');
            return;
        }
        setCreateLoading(true);
        setCreateError('');

        try {
            // Using addDoc allows Firestore to auto-generate a unique ID, preventing collision and simplifing the flow.
            await addDoc(collection(db, 'artifacts', appId, 'users'), {
                name: newStudent.name,
                phone: newStudent.phone,
                role: 'student',
                anamnesisComplete: false,
                createdAt: new Date().toISOString()
            });

            // Fechar modal imediatamente
            setIsAddModalOpen(false);
            setNewStudent({ name: '', phone: '' });
        } catch (e: any) {
            console.error("Firestore Error:", e);
            setCreateError('Erro técnico ao conectar com o servidor.');
        } finally {
            setCreateLoading(false);
        }
    };

    if (selectedStudentId) {
        const student = students.find((s: UserProfile) => s.id === selectedStudentId);
        if (!student) return <div>Erro ao carregar aluno.</div>;

        return (
            <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <button onClick={() => onSelectStudent(null)} className="flex items-center gap-2 text-slate-400 hover:text-blue-600 transition-colors font-bold uppercase text-xs tracking-widest mb-4">
                    <ArrowRight className="rotate-180" size={16} /> Voltar para Lista
                </button>

                <div className="flex flex-col md:flex-row gap-8">
                    <div className="w-full md:w-5/12 space-y-6">
                        <StudentProfileCard student={student} />
                    </div>
                    <div className="w-full md:w-7/12">
                        <WorkoutManager student={student} />
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto">
            <div className="flex justify-between items-end mb-12 border-b border-slate-200 pb-6">
                <div>
                    <h2 className="text-4xl font-black italic uppercase tracking-tighter text-slate-900">Meus Atletas</h2>
                    <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-2">Gestão de Squad</p>
                </div>
                <Button onClick={() => setIsAddModalOpen(true)} className="shadow-xl">
                    <Plus size={20} /> Novo Atleta
                </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {students.map((s: UserProfile) => (
                    <Card key={s.id} onClick={() => onSelectStudent(s.id)} className="group cursor-pointer hover:border-blue-500/30">
                        <div className="flex items-center justify-between mb-6">
                            <div className="w-16 h-16 bg-gradient-to-br from-slate-100 to-slate-200 rounded-2xl flex items-center justify-center text-slate-600 font-black text-2xl shadow-inner">
                                {s.name.charAt(0)}
                            </div>
                            <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wide ${s.anamnesisComplete ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                                {s.anamnesisComplete ? 'Ativo' : 'Pendente'}
                            </div>
                        </div>
                        <h3 className="text-xl font-black uppercase italic text-slate-800 truncate">{s.name}</h3>
                        <p className="text-xs font-bold text-slate-400 mt-1 flex items-center gap-2"><Phone size={12}/> {s.phone}</p>

                        <div className="mt-8 pt-6 border-t border-slate-50 flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity">
                            <span className="text-xs font-bold text-blue-600 uppercase">Gerenciar</span>
                            <ArrowRight size={16} className="text-blue-600" />
                        </div>
                    </Card>
                ))}
            </div>

            {isAddModalOpen && (
                <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
                    <Card className="max-w-md w-full">
                        <div className="flex justify-between mb-6"><h3 className="text-xl font-black italic uppercase">Cadastrar Atleta</h3><button onClick={() => setIsAddModalOpen(false)}><X /></button></div>
                        <div className="space-y-4">
                            <Input label="Nome Completo" value={newStudent.name} onChange={(v: string) => setNewStudent({...newStudent, name: v})} placeholder="Ex: João Silva" />
                            <Input label="Celular (Login)" value={newStudent.phone} onChange={(v: string) => setNewStudent({...newStudent, phone: v})} placeholder="Ex: 11999999999" type="tel" />
                            {createError && <p className="text-rose-500 text-xs font-bold flex items-center gap-2"><AlertCircle size={14}/> {createError}</p>}
                            <Button onClick={handleAddStudent} loading={createLoading} className="w-full mt-4">Criar Perfil</Button>
                        </div>
                    </Card>
                </div>
            )}
        </div>
    );
}

function StudentProfileCard({ student }: { student: UserProfile }) {
    const [isEditing, setIsEditing] = useState(false);
    const [data, setData] = useState(student);
    const [saving, setSaving] = useState(false);

    const handleSave = async () => {
        setSaving(true);
        const updated = { ...data, anamnesisComplete: true };
        await setDoc(doc(db, 'artifacts', appId, 'users', student.id), updated, { merge: true });
        setSaving(false);
        setIsEditing(false);
    };

    if (isEditing) {
        return (
            <Card className="border-l-4 border-l-blue-500 h-full">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black italic uppercase text-lg">Anamnese Completa</h3>
                    <button onClick={() => setIsEditing(false)}><X size={20} className="text-slate-400"/></button>
                </div>
                <div className="space-y-6 max-h-[70vh] overflow-y-auto pr-2 custom-scrollbar">

                    {/* Avaliação Física */}
                    <div className="space-y-4">
                        <h4 className="text-[10px] font-black uppercase text-blue-500 tracking-widest flex items-center gap-2"><Scale size={14}/> Avaliação Física</h4>
                        <div className="grid grid-cols-2 gap-3">
                            <Input label="Idade" type="number" value={data.age || ''} onChange={(v: string) => setData({...data, age: v})} />
                            <Input label="Peso (kg)" type="number" value={data.weight || ''} onChange={(v: string) => setData({...data, weight: v})} />
                            <Input label="Altura (cm)" type="number" value={data.height || ''} onChange={(v: string) => setData({...data, height: v})} />
                            <Input label="FC Repouso (bpm)" type="number" value={data.restingHeartRate || ''} onChange={(v: string) => setData({...data, restingHeartRate: v})} />
                        </div>
                    </div>

                    {/* Histórico e Saúde */}
                    <div className="space-y-4">
                        <h4 className="text-[10px] font-black uppercase text-blue-500 tracking-widest flex items-center gap-2"><Stethoscope size={14}/> Histórico Clínico</h4>
                        <TextArea label="Lesões Prévias" value={data.injuries || ''} onChange={(v: string) => setData({...data, injuries: v})} placeholder="Histórico de lesões..." />
                        <TextArea label="Medicamentos / Condições" value={data.medications || ''} onChange={(v: string) => setData({...data, medications: v})} placeholder="Uso contínuo de..." />
                    </div>

                    {/* Rotina e Objetivos */}
                    <div className="space-y-4">
                        <h4 className="text-[10px] font-black uppercase text-blue-500 tracking-widest flex items-center gap-2"><ClipboardList size={14}/> Rotina de Treino</h4>
                         <Select label="Objetivo Principal" value={data.goal || 'condition'} onChange={(v: string) => setData({...data, goal: v})} options={[
                                {value: 'condition', label: 'Condicionamento Geral'},
                                {value: 'weight_loss', label: 'Perda de Peso'},
                                {value: '5k', label: 'Prova 5km'},
                                {value: '10k', label: 'Prova 10km'},
                                {value: '21k', label: 'Meia Maratona'},
                                {value: '42k', label: 'Maratona'}
                            ]} />
                        <Input label="Experiência na Corrida" value={data.runningExperience || ''} onChange={(v: string) => setData({...data, runningExperience: v})} placeholder="Ex: Corre há 2 anos..." />
                        <Input label="Disponibilidade (Dias/Semana)" value={data.availability || ''} onChange={(v: string) => setData({...data, availability: v})} placeholder="Ex: Seg, Qua, Sex" />
                    </div>

                    <Button onClick={handleSave} loading={saving} className="w-full">Salvar Avaliação</Button>
                </div>
            </Card>
        )
    }

    return (
        <Card className="h-full relative overflow-hidden flex flex-col">
            <div className="flex items-center gap-4 mb-8">
                <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-white text-3xl font-black shadow-xl shadow-blue-500/20 shrink-0">
                    {student.name.charAt(0)}
                </div>
                <div>
                    <h3 className="text-2xl font-black italic uppercase leading-none">{student.name}</h3>
                    <p className="text-xs font-bold text-slate-400 mt-2 uppercase tracking-wide">Perfil do Atleta</p>
                </div>
            </div>

            <div className="space-y-6 flex-1">
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-4 rounded-2xl">
                        <p className="text-[10px] font-black text-slate-400 uppercase">Peso</p>
                        <p className="text-2xl font-black text-slate-800">{student.weight || '--'} <span className="text-xs text-slate-400 font-medium">kg</span></p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl">
                        <p className="text-[10px] font-black text-slate-400 uppercase">Altura</p>
                        <p className="text-2xl font-black text-slate-800">{student.height || '--'} <span className="text-xs text-slate-400 font-medium">cm</span></p>
                    </div>
                </div>

                <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Objetivo Atual</p>
                    <p className="text-lg font-bold text-blue-600 flex items-center gap-2">
                        <Target size={18} /> 
                        {student.goal ? student.goal.toUpperCase() : 'NÃO DEFINIDO'}
                    </p>
                </div>

                <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 flex-1">
                     <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Observações</p>
                     <p className="text-sm font-medium text-slate-600">{student.injuries ? `⚠️ ${student.injuries}` : 'Nenhuma lesão registrada.'}</p>
                </div>
            </div>

            <Button variant="outline" onClick={() => setIsEditing(true)} className="w-full mt-6">
                {student.anamnesisComplete ? 'Editar Avaliação' : 'Iniciar Avaliação'}
            </Button>
        </Card>
    )
}

function WorkoutManager({ student }: { student: UserProfile }) {
    const [workouts, setWorkouts] = useState<WorkoutModel[]>([]);
    const [isCreating, setIsCreating] = useState(false);

    useEffect(() => {
        const q = collection(db, 'artifacts', appId, 'workouts');
        const unsub = onSnapshot(q, (snap) => {
            const data = snap.docs.map(d => ({id: d.id, ...d.data()} as WorkoutModel));
            setWorkouts(data.filter(w => w.studentId === student.id));
        });
        return () => unsub();
    }, [student.id]);

    const deleteWorkout = async (id: string) => {
        if(confirm("Tem certeza que deseja excluir este treino?")) {
            await deleteDoc(doc(db, 'artifacts', appId, 'workouts', id));
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100">
                <h3 className="text-xl font-black italic uppercase tracking-tighter flex items-center gap-3">
                    <Flame className="text-orange-500" /> Prescrição de Treinos
                </h3>
                <Button onClick={() => setIsCreating(true)} variant="secondary" className="px-8">
                   <Plus size={18} /> Novo Treino
                </Button>
            </div>

            {isCreating && (
                <WorkoutBuilder 
                    studentId={student.id} 
                    onClose={() => setIsCreating(false)} 
                />
            )}

            <div className="grid gap-4">
                {workouts.length === 0 ? (
                    <div className="text-center py-12 text-slate-400 bg-white rounded-[2rem] border border-slate-100 border-dashed">
                        <p className="font-bold">Nenhum treino prescrito.</p>
                    </div>
                ) : (
                   workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek)).map(w => (
                       <WorkoutCard key={w.id} workout={w} onDelete={() => deleteWorkout(w.id)} />
                   )) 
                )}
            </div>

            <WorkoutLegend />
        </div>
    )
}

function WorkoutBuilder({ studentId, onClose }: { studentId: string, onClose: () => void }) {
    const [type, setType] = useState<WorkoutModel['type']>('longao');
    const [day, setDay] = useState('Segunda');
    const [loading, setLoading] = useState(false);

    // Form States
    const [common, setCommon] = useState({ distance: '', time: '', pace: '', description: '', warmup: '10', cooldown: '5' });
    const [interval, setInterval] = useState({ sets: '1', reps: '10', stim: '2', rec: '1', recType: 'min' });
    const [fartlek, setFartlek] = useState({ fast: '1', slow: '1' });

    const handleSave = async () => {
        setLoading(true);
        try {
            const payload: any = {
                studentId,
                type,
                dayOfWeek: day,
                warmupTime: common.warmup,
                cooldownTime: common.cooldown,
                description: common.description,
                createdAt: new Date().toISOString()
            };

            // Calculate total time approximate based on inputs
            let estimatedTotal = 0;
            const w = Number(common.warmup) || 0;
            const c = Number(common.cooldown) || 0;

            if (type === 'longao' || type === 'ritmo' || type === 'regenerativo') {
                payload.distance = common.distance;
                payload.pace = common.pace;
                payload.totalTime = common.time; 
            } else if (type === 'tiro' || type === 'subida') {
                payload.sets = interval.sets;
                payload.reps = interval.reps;
                payload.stimulusTime = interval.stim;
                payload.recoveryTime = interval.rec;

                const sets = Number(interval.sets) || 1;
                const reps = Number(interval.reps) || 1;
                const stim = Number(interval.stim) || 0;
                const rec = Number(interval.rec) || 0;
                estimatedTotal = w + c + (sets * (reps * (stim + rec)));
                payload.totalTime = String(estimatedTotal);
            } else if (type === 'fartlek') {
                payload.totalTime = common.time;
                payload.fastTime = fartlek.fast;
                payload.slowTime = fartlek.slow;
            }

            await addDoc(collection(db, 'artifacts', appId, 'workouts'), payload);
            onClose();
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    return (
        <Card className="border-2 border-blue-600 bg-slate-50 relative animate-in zoom-in-95 duration-200">
            <button onClick={onClose} className="absolute top-4 right-4 text-slate-400 hover:text-slate-800"><X /></button>
            <h4 className="text-lg font-black italic uppercase mb-6 text-blue-700">Montar Sessão de Treino</h4>

            <div className="grid grid-cols-2 gap-4 mb-6">
                <Select label="Dia da Semana" value={day} onChange={setDay} options={[
                    {value: 'Segunda', label: 'Segunda-feira'},
                    {value: 'Terça', label: 'Terça-feira'},
                    {value: 'Quarta', label: 'Quarta-feira'},
                    {value: 'Quinta', label: 'Quinta-feira'},
                    {value: 'Sexta', label: 'Sexta-feira'},
                    {value: 'Sábado', label: 'Sábado'},
                    {value: 'Domingo', label: 'Domingo'}
                ]} />
                <Select label="Método" value={type} onChange={setType} options={[
                    {value: 'longao', label: 'Longão (Volume)'},
                    {value: 'tiro', label: 'Intervalado (Tiros)'},
                    {value: 'fartlek', label: 'Fartlek (Variado)'},
                    {value: 'ritmo', label: 'Tempo Run (Ritmo)'},
                    {value: 'subida', label: 'Força (Subidas)'},
                    {value: 'regenerativo', label: 'Regenerativo (Leve)'}
                ]} />
            </div>

            <div className="bg-white p-6 rounded-2xl border border-slate-200 mb-6 space-y-4">
                {/* Dynamic Fields */}
                {(type === 'longao' || type === 'ritmo' || type === 'regenerativo') && (
                    <div className="grid grid-cols-2 gap-4">
                        <Input label="Distância (km)" type="number" value={common.distance} onChange={(v: string) => setCommon({...common, distance: v})} />
                        <Input label="Tempo Total (min)" type="number" value={common.time} onChange={(v: string) => setCommon({...common, time: v})} />
                        <Input label="Pace Alvo (min/km)" value={common.pace} onChange={(v: string) => setCommon({...common, pace: v})} className="col-span-2" />
                    </div>
                )}

                {(type === 'tiro' || type === 'subida') && (
                    <div className="space-y-4">
                        <div className="grid grid-cols-3 gap-4">
                            <Input label="Aquecimento (min)" type="number" value={common.warmup} onChange={(v: string) => setCommon({...common, warmup: v})} />
                            <Input label="Desaquecimento" type="number" value={common.cooldown} onChange={(v: string) => setCommon({...common, cooldown: v})} />
                            <Input label="Séries (Blocos)" type="number" value={interval.sets} onChange={(v: string) => setInterval({...interval, sets: v})} />
                        </div>
                        <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 grid grid-cols-3 gap-4">
                            <Input label="Repetições" type="number" value={interval.reps} onChange={(v: string) => setInterval({...interval, reps: v})} />
                            <Input label="Estímulo (min/dist)" value={interval.stim} onChange={(v: string) => setInterval({...interval, stim: v})} />
                            <Input label="Recuperação (min)" value={interval.rec} onChange={(v: string) => setInterval({...interval, rec: v})} />
                        </div>
                    </div>
                )}

                {type === 'fartlek' && (
                    <div className="space-y-4">
                         <div className="grid grid-cols-2 gap-4">
                            <Input label="Tempo Total (min)" type="number" value={common.time} onChange={(v: string) => setCommon({...common, time: v})} />
                            <Input label="Aquecimento (min)" type="number" value={common.warmup} onChange={(v: string) => setCommon({...common, warmup: v})} />
                         </div>
                         <div className="p-4 bg-purple-50 rounded-xl border border-purple-100 grid grid-cols-2 gap-4">
                            <Input label="Forte (min)" type="number" value={fartlek.fast} onChange={(v: string) => setFartlek({...fartlek, fast: v})} />
                            <Input label="Fraco (min)" type="number" value={fartlek.slow} onChange={(v: string) => setFartlek({...fartlek, slow: v})} />
                         </div>
                    </div>
                )}

                <TextArea label="Observações Técnicas" value={common.description} onChange={(v: string) => setCommon({...common, description: v})} placeholder="Ex: Terreno plano, focar na postura..." />
            </div>

            <Button onClick={handleSave} loading={loading} className="w-full text-lg">Confirmar Prescrição</Button>
        </Card>
    );
}

function WorkoutCard({ workout, onDelete }: { workout: WorkoutModel, onDelete?: () => void, key?: any }) {
    const colorMap: any = {
        longao: 'bg-indigo-600',
        tiro: 'bg-rose-500',
        fartlek: 'bg-purple-600',
        ritmo: 'bg-orange-500',
        subida: 'bg-amber-600',
        regenerativo: 'bg-emerald-500'
    };

    const bgColor = colorMap[workout.type] || 'bg-slate-500';

    return (
        <Card className="relative overflow-hidden group border-none ring-1 ring-slate-100 shadow-lg">
            <div className={`absolute top-0 left-0 w-2 h-full ${bgColor}`} />

            <div className="flex justify-between items-start pl-4">
                <div>
                    <div className="flex items-center gap-3 mb-2">
                         <Badge>{workout.dayOfWeek}</Badge>
                         <span className="text-[10px] font-black uppercase tracking-widest text-slate-300">{workout.totalTime} MIN TOTAIS</span>
                    </div>
                    <h4 className="text-2xl font-black italic uppercase tracking-tighter text-slate-800">{workout.type}</h4>

                    <div className="mt-4 text-sm text-slate-600 font-medium leading-relaxed max-w-md">
                        {workout.type === 'tiro' || workout.type === 'subida' ? (
                            <span>{workout.warmupTime}' AQ + <strong>{workout.sets} x ({workout.reps} Blocos de {workout.stimulusTime}' CO : {workout.recoveryTime}' Rec)</strong> + {workout.cooldownTime}' VC.</span>
                        ) : workout.type === 'fartlek' ? (
                            <span>{workout.warmupTime}' AQ + Alternar <strong>{workout.fastTime}' CO : {workout.slowTime}' Rec</strong> até completar {workout.totalTime} min Totais + VC Livre.</span>
                        ) : (
                            <span>{workout.distance}km CO @ {workout.pace || 'Livre'}</span>
                        )}
                    </div>

                    {workout.description && <p className="mt-2 text-xs italic text-slate-400">Obs: {workout.description}</p>}
                </div>

                <div className="flex flex-col items-end gap-2">
                    <div className={`w-12 h-12 rounded-2xl ${bgColor} flex items-center justify-center text-white shadow-lg shadow-current/30`}>
                        {workout.type === 'tiro' ? <Timer /> : workout.type === 'subida' ? <Mountain /> : workout.type === 'fartlek' ? <Zap /> : <Activity />}
                    </div>
                    {onDelete && (
                         <button onClick={onDelete} className="mt-2 p-2 text-slate-300 hover:text-rose-500 transition-colors"><Trash2 size={18}/></button>
                    )}
                </div>
            </div>
        </Card>
    )
}

function StudentView({ profile }: { profile: UserProfile }) {
    const [workouts, setWorkouts] = useState<WorkoutModel[]>([]);

    useEffect(() => {
        const q = collection(db, 'artifacts', appId, 'workouts');
        const unsub = onSnapshot(q, (snap) => {
            const data = snap.docs.map(d => ({id: d.id, ...d.data()} as WorkoutModel));
            setWorkouts(data.filter(w => w.studentId === profile.id));
        });
        return () => unsub();
    }, [profile.id]);

    return (
        <div className="max-w-xl mx-auto pb-20">
            <div className="mb-10 text-center">
                 <h2 className="text-3xl font-black italic uppercase tracking-tighter">Olá, {profile.name.split(' ')[0]}</h2>
                 <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-2">Sua Planilha da Semana</p>
            </div>

            <div className="space-y-6">
                {workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek)).map(w => (
                    <WorkoutCard key={w.id} workout={w} />
                ))}
                {workouts.length === 0 && (
                    <div className="bg-white p-12 rounded-[2rem] text-center border border-slate-100 shadow-sm">
                        <Clock size={48} className="mx-auto text-slate-200 mb-4" />
                        <p className="font-bold text-slate-400">Aguardando prescrição do treinador.</p>
                    </div>
                )}
            </div>

            <WorkoutLegend />
        </div>
    )
}

// --- HELPERS ---

function getDayIndex(day: string) {
  const days = ['Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado', 'Domingo'];
  return days.indexOf(day);
}

function formatPace(decimalPace: number) {
  if (!decimalPace || isNaN(decimalPace) || !isFinite(decimalPace)) return '0:00';
  const min = Math.floor(decimalPace);
  const sec = Math.round((decimalPace - min) * 60);
  return `${min}:${sec < 10 ? '0' : ''}${sec} min/km`;
}

