function ProfessorDashboard({ students, selectedStudentId, onSelectStudent }: any) {
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [newStudent, setNewStudent] = useState({ name: '', phone: '' });
    const [createLoading, setCreateLoading] = useState(false);
    const [createError, setCreateError] = useState('');

    // Robust Add Student Logic
    const handleAddStudent = async () => {
        if (!newStudent.name || !newStudent.phone) {
            setCreateError('Por favor, preencha todos os campos.');
            return;
        }
        setCreateLoading(true);
        setCreateError('');

        try {
            // Using addDoc allows Firestore to auto-generate a unique ID, preventing collision and simplifing the flow.
            const docRef = await addDoc(collection(db, 'artifacts', appId, 'users'), {
                name: newStudent.name,
                phone: newStudent.phone,
                role: 'student',
                anamnesisComplete: false,
                createdAt: new Date().toISOString()
            });

            // Fechar modal imediatamente
            setIsAddModalOpen(false);
            setNewStudent({ name: '', phone: '' });

            // Abrir automaticamente o perfil do novo aluno
            onSelectStudent(docRef.id);

        } catch (e: any) {
            console.error("Firestore Error:", e);
            setCreateError('Erro técnico ao conectar com o servidor.');
        } finally {
            setCreateLoading(false);
        }
    };

    if (selectedStudentId) {
        const student = students.find((s: UserProfile) => s.id === selectedStudentId);
        if (!student) return <div>Erro ao carregar aluno.</div>;

        return (
            <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <button onClick={() => onSelectStudent(null)} className="flex items-center gap-2 text-slate-400 hover:text-blue-600 transition-colors font-bold uppercase text-xs tracking-widest mb-4">
                    <ArrowRight className="rotate-180" size={16} /> Voltar para Lista
                </button>

                <div className="flex flex-col md:flex-row gap-8">
                    <div className="w-full md:w-5/12 space-y-6">
                        <StudentProfileCard student={student} />
                    </div>
                    <div className="w-full md:w-7/12">
                        <WorkoutManager student={student} />
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto">
            <div className="flex justify-between items-end mb-12 border-b border-slate-200 pb-6">
                <div>
                    <h2 className="text-4xl font-black italic uppercase tracking-tighter text-slate-900">Meus Atletas</h2>
                    <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-2">Gestão de Squad</p>
                </div>
                <Button onClick={() => setIsAddModalOpen(true)} className="shadow-xl">
                    <Plus size={20} /> Novo Atleta
                </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {students.map((s: UserProfile) => (
                    <Card key={s.id} onClick={() => onSelectStudent(s.id)} className="group cursor-pointer hover:border-blue-500/30">
                        <div className="flex items-center justify-between mb-6">
                            <div className="w-16 h-16 bg-gradient-to-br from-slate-100 to-slate-200 rounded-2xl flex items-center justify-center text-slate-600 font-black text-2xl shadow-inner">
                                {s.name.charAt(0)}
                            </div>
                            <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wide ${s.anamnesisComplete ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                                {s.anamnesisComplete ? 'Ativo' : 'Pendente'}
                            </div>
                        </div>
                        <h3 className="text-xl font-black uppercase italic text-slate-800 truncate">{s.name}</h3>
                        <p className="text-xs font-bold text-slate-400 mt-1 flex items-center gap-2"><Phone size={12}/> {s.phone}</p>

                        <div className="mt-8 pt-6 border-t border-slate-50 flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity">
                            <span className="text-xs font-bold text-blue-600 uppercase">Gerenciar</span>
                            <ArrowRight size={16} className="text-blue-600" />
