                            <div className="grid grid-cols-2 gap-4">
                                <Input label="FC Repouso (bpm)" type="number" value={formData.restingHeartRate || ''} onChange={(v: string) => updateData('restingHeartRate', v)} placeholder="Ex: 60" />
                                <Input label="FC Máxima (Estimada ou Teste)" type="number" value={formData.maxHeartRate || ''} onChange={(v: string) => updateData('maxHeartRate', v)} placeholder="Ex: 185" />
                            </div>
                            <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 text-blue-800 text-sm">
                                <strong>Nota:</strong> A FC Repouso é crucial para o cálculo das zonas de treino pela fórmula de Karvonen.
                            </div>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                            <TextArea label="Lesões Atuais ou Recentes" value={formData.injuries || ''} onChange={(v: string) => updateData('injuries', v)} placeholder="Descreva locais, dor e limitações..." />
                            <TextArea label="Medicamentos de Uso Contínuo" value={formData.medications || ''} onChange={(v: string) => updateData('medications', v)} placeholder="Nome e dosagem..." />
                            <TextArea label="Histórico Cirúrgico Relevante" value={formData.surgery || ''} onChange={(v: string) => updateData('surgery', v)} placeholder="Cirurgias ortopédicas ou cardíacas..." />
                             <Select label="Atestado Médico / Liberação" value={formData.medicalClearance ? 'yes' : 'no'} onChange={(v: string) => updateData('medicalClearance', v === 'yes')} options={[
                                {value: 'yes', label: 'Sim, apto para exercício vigoroso'}, {value: 'no', label: 'Não / Pendente'}
                            ]} />
                        </div>
                    )}

                    {step === 4 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                             <div className="grid grid-cols-2 gap-4">
                                <Input label="Anos de Corrida" type="number" value={formData.runningYears || ''} onChange={(v: string) => updateData('runningYears', v)} />
                                <Input label="Volume Semanal Atual (km)" type="number" value={formData.weeklyVolume || ''} onChange={(v: string) => updateData('weeklyVolume', v)} />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Melhor 5km (Min)" value={formData.best5k || ''} onChange={(v: string) => updateData('best5k', v)} placeholder="00:00" />
                                <Input label="Melhor 10km (Min)" value={formData.best10k || ''} onChange={(v: string) => updateData('best10k', v)} placeholder="00:00" />
                            </div>
                            <Select label="Objetivo Principal" value={formData.mainGoal} onChange={(v: string) => updateData('mainGoal', v)} options={[
                                {value: 'health', label: 'Saúde & Qualidade de Vida'},
                                {value: 'weight_loss', label: 'Emagrecimento'},
                                {value: 'performance_5k', label: 'Performance 5km'},
                                {value: 'performance_10k', label: 'Performance 10km'},
                                {value: 'half_marathon', label: 'Meia Maratona (21k)'},
                                {value: 'marathon', label: 'Maratona (42k)'}
                            ]} />
                            <Select label="Disponibilidade Semanal" value={formData.availabilityDays} onChange={(v: string) => updateData('availabilityDays', v)} options={[
                                {value: '2', label: '2 Dias (Manutenção)'},
                                {value: '3', label: '3 Dias (Mínimo Recomendado)'},
                                {value: '4', label: '4 Dias (Evolução)'},
                                {value: '5', label: '5 Dias (Performance)'},
                                {value: '6', label: '6 Dias (Alto Rendimento)'}
                            ]} />
                        </div>
                    )}
                </Card>

                <div className="flex justify-between items-center">
                    <Button variant="ghost" disabled={step === 1} onClick={() => setStep(s => s - 1)}>
                        <ChevronLeft /> Voltar
                    </Button>

                    {step < 4 ? (
                         <Button onClick={() => setStep(s => s + 1)}>
                            Próximo <ChevronRight />
                        </Button>
                    ) : (
                        <Button variant="success" loading={loading} onClick={handleFinish} className="px-8">
                            <Save size={18} /> Finalizar Cadastro
                        </Button>
                    )}
                </div>
            </div>
        </div>
    )
}

