function WorkoutCard({ workout, onDelete }: { workout: WorkoutModel, onDelete?: () => void, key?: any }) {
    const colorMap: any = {
        longao: 'bg-indigo-600',
        tiro: 'bg-rose-500',
        fartlek: 'bg-purple-600',
        ritmo: 'bg-orange-500',
        subida: 'bg-amber-600',
        regenerativo: 'bg-emerald-500'
    };

    const bgColor = colorMap[workout.type] || 'bg-slate-500';

    return (
        <Card className="relative overflow-hidden group border-none ring-1 ring-slate-100 shadow-lg">
            <div className={`absolute top-0 left-0 w-2 h-full ${bgColor}`} />

            <div className="flex justify-between items-start pl-4">
                <div>
                    <div className="flex items-center gap-3 mb-2">
                         <Badge>{workout.dayOfWeek}</Badge>
                         <span className="text-[10px] font-black uppercase tracking-widest text-slate-300">{workout.totalTime} MIN TOTAIS</span>
                    </div>
                    <h4 className="text-2xl font-black italic uppercase tracking-tighter text-slate-800">{workout.type}</h4>

                    <div className="mt-4 text-sm text-slate-600 font-medium leading-relaxed max-w-md">
                        {workout.type === 'tiro' || workout.type === 'subida' ? (
                            <span>{workout.warmupTime}' AQ + <strong>{workout.sets} x ({workout.reps} Blocos de {workout.stimulusTime}' CO : {workout.recoveryTime}' Rec)</strong> + {workout.cooldownTime}' VC.</span>
                        ) : workout.type === 'fartlek' ? (
                            <span>{workout.warmupTime}' AQ + Alternar <strong>{workout.fastTime}' CO : {workout.slowTime}' Rec</strong> até completar {workout.totalTime} min Totais + VC Livre.</span>
                        ) : (
                            <span>{workout.distance}km CO @ {workout.pace || 'Livre'}</span>
                        )}
                    </div>

                    {workout.description && <p className="mt-2 text-xs italic text-slate-400">Obs: {workout.description}</p>}
                </div>

                <div className="flex flex-col items-end gap-2">
                    <div className={`w-12 h-12 rounded-2xl ${bgColor} flex items-center justify-center text-white shadow-lg shadow-current/30`}>
                        {workout.type === 'tiro' ? <Timer /> : workout.type === 'subida' ? <Mountain /> : workout.type === 'fartlek' ? <Zap /> : <Activity />}
                    </div>
                    {onDelete && (
                         <button onClick={onDelete} className="mt-2 p-2 text-slate-300 hover:text-rose-500 transition-colors"><Trash2 size={18}/></button>
                    )}
                </div>
            </div>
        </Card>
    )
}

function StudentView({ profile }: { profile: UserProfile }) {
    const [workouts, setWorkouts] = useState<WorkoutModel[]>([]);

    useEffect(() => {
        const q = collection(db, 'artifacts', appId, 'workouts');
        const unsub = onSnapshot(q, (snap) => {
            const data = snap.docs.map(d => ({id: d.id, ...d.data()} as WorkoutModel));
            setWorkouts(data.filter(w => w.studentId === profile.id));
        });
        return () => unsub();
    }, [profile.id]);

    return (
        <div className="max-w-xl mx-auto pb-20">
            <div className="mb-10 text-center">
                 <h2 className="text-3xl font-black italic uppercase tracking-tighter">Olá, {profile.name.split(' ')[0]}</h2>
                 <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-2">Sua Planilha da Semana</p>
            </div>

            <div className="space-y-6">
                {workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek)).map(w => (
                    <WorkoutCard key={w.id} workout={w} />
                ))}
                {workouts.length === 0 && (
                    <div className="bg-white p-12 rounded-[2rem] text-center border border-slate-100 shadow-sm">
                        <Clock size={48} className="mx-auto text-slate-200 mb-4" />
                        <p className="font-bold text-slate-400">Aguardando prescrição do treinador.</p>
                    </div>
                )}
            </div>

            <WorkoutLegend />
        </div>
    )
}

// --- HELPERS ---

function getDayIndex(day: string) {
  const days = ['Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado', 'Domingo'];
  return days.indexOf(day);
}

function formatPace(decimalPace: number) {
  if (!decimalPace || isNaN(decimalPace) || !isFinite(decimalPace)) return '0:00';
  const min = Math.floor(decimalPace);
  const sec = Math.round((decimalPace - min) * 60);
  return `${min}:${sec < 10 ? '0' : ''}${sec} min/km`;
}

