function AthleteAssessmentWizard({ onCancel, onComplete }: { onCancel: () => void, onComplete: (id: string) => void }) {
    const [step, setStep] = useState(1);
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState<Partial<UserProfile>>({
        role: 'student',
        anamnesisComplete: true,
        gender: 'male',
        mainGoal: 'health',
        availabilityDays: '3',
        medicalClearance: true
    });

    // Auto-calculate Max Heart Rate when Birth Date or Gender changes
    useEffect(() => {
        if (formData.birthDate && formData.gender) {
            const birthDate = new Date(formData.birthDate);
            if (!isNaN(birthDate.getTime())) {
                const today = new Date();
                let age = today.getFullYear() - birthDate.getFullYear();
                const m = today.getMonth() - birthDate.getMonth();
                if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
                    age--;
                }

                if (age > 0) {
                    const calculatedMax = formData.gender === 'female' ? (226 - age) : (220 - age);
                    setFormData(prev => {
                        // Avoid infinite loop if value is already set to the calculated one
                        if (prev.maxHeartRate === calculatedMax.toString()) return prev;
                        return { ...prev, maxHeartRate: calculatedMax.toString() };
                    });
                }
            }
        }
    }, [formData.birthDate, formData.gender]);

    const updateData = (key: keyof UserProfile, value: any) => {
        setFormData(prev => ({ ...prev, [key]: value }));
    }

    const handleFinish = async () => {
        if (!formData.name || !formData.phone) {
            alert("Nome e Celular são obrigatórios para o cadastro.");
            return;
        }
        setLoading(true);
        try {
            const docRef = await addDoc(collection(db, 'artifacts', appId, 'users'), {
                ...formData,
                createdAt: new Date().toISOString()
            });
            // Short delay to ensure Firestore propagation or local cache update before redirecting
            setTimeout(() => {
                onComplete(docRef.id);
            }, 500);
        } catch (e) {
            console.error("Erro ao salvar:", e);
            alert("Houve um erro ao salvar o perfil. Tente novamente.");
            setLoading(false); // Enable retry
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 flex flex-col">
            <div className="h-2 w-full bg-slate-200">
                <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${(step/4)*100}%` }} />
            </div>

            <div className="flex-1 max-w-3xl mx-auto w-full p-6 flex flex-col justify-center">
                <div className="mb-8">
                    <button onClick={onCancel} className="text-slate-400 hover:text-slate-800 flex items-center gap-2 text-sm font-bold uppercase tracking-widest mb-4">
                        <X size={16} /> Cancelar Avaliação
                    </button>
                    <h2 className="text-4xl font-black italic uppercase text-slate-900 leading-none">
                        {step === 1 && "Dados Cadastrais"}
                        {step === 2 && "Avaliação Física"}
                        {step === 3 && "Anamnese & Saúde"}
                        {step === 4 && "Histórico & Objetivos"}
                    </h2>
                    <p className="text-slate-500 font-medium mt-2">Etapa {step} de 4: Vamos construir o perfil completo do atleta.</p>
                </div>

                <Card className="flex-1 max-h-[60vh] overflow-y-auto mb-8 shadow-xl border-blue-100">
                    {step === 1 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                            <Input label="Nome Completo" value={formData.name || ''} onChange={(v: string) => updateData('name', v)} placeholder="Nome do Atleta" />
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Celular (Login)" value={formData.phone || ''} onChange={(v: string) => updateData('phone', v)} placeholder="11999999999" type="tel" />
                                <Input label="Data de Nascimento" value={formData.birthDate || ''} onChange={(v: string) => updateData('birthDate', v)} type="date" />
                            </div>
                            <Select label="Gênero Biológico" value={formData.gender} onChange={(v: string) => updateData('gender', v)} options={[
                                {value: 'male', label: 'Masculino'}, {value: 'female', label: 'Feminino'}
                            ]} />
                        </div>
                    )}

                    {step === 2 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Peso (kg)" type="number" value={formData.weight || ''} onChange={(v: string) => updateData('weight', v)} />
                                <Input label="Altura (cm)" type="number" value={formData.height || ''} onChange={(v: string) => updateData('height', v)} />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="FC Repouso (bpm)" type="number" value={formData.restingHeartRate || ''} onChange={(v: string) => updateData('restingHeartRate', v)} placeholder="Ex: 60" />
                                <div className="relative">
                                    <Input 
                                        label="FC Máxima (Estimada)" 
                                        type="number" 
                                        value={formData.maxHeartRate || ''} 
                                        onChange={(v: string) => updateData('maxHeartRate', v)} 
                                        placeholder="Calculando..."
                                        className="bg-blue-50/50 border-blue-200 text-blue-800"
                                    />
                                    <Sparkles className="absolute right-3 top-9 text-blue-400 pointer-events-none" size={16} />
                                </div>
                            </div>
                            <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 text-blue-800 text-sm">
                                <strong>Nota:</strong> A FC Máxima foi calculada automaticamente baseada na idade ({formData.gender === 'male' ? '220' : '226'} - idade), mas pode ser ajustada caso possua teste ergoespirométrico.
                            </div>
