            <div className="grid gap-4">
                {filtered.map(student => (
                    <Card key={student.id} onClick={() => { setSelectedForAuth(student); setError(""); setPhoneInput(""); }} className="flex items-center justify-between p-6 hover:ring-2 hover:ring-blue-500/20">
                        <div className="flex items-center gap-4">
                            <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-500 font-black text-xl">
                                {student.name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-bold text-lg text-slate-900 leading-tight">{student.name}</h3>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Atleta</p>
