function StudentView({ profile }: { profile: UserProfile }) {
    const [workouts, setWorkouts] = useState<WorkoutModel[]>([]);

    useEffect(() => {
        if (!profile.id) return;
        const q = collection(db, 'artifacts', appId, 'workouts');
        const unsub = onSnapshot(q, (snap) => {
            const data = snap.docs.map(d => ({id: d.id, ...d.data()} as WorkoutModel));
            setWorkouts(data.filter(w => w.studentId === profile.id));
        });
        return () => unsub();
    }, [profile.id]);

    const sortedWorkouts = workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek));

    // Simple today logic
    const daysMap = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];
    const todayName = daysMap[new Date().getDay()];
    const todayWorkout = workouts.find(w => w.dayOfWeek.includes(todayName.split('-')[0]));

    return (
        <div className="max-w-md mx-auto space-y-8 pb-24 animate-in fade-in duration-500">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-black italic uppercase tracking-tighter text-slate-900">
                        Olá, {profile.name.split(' ')[0]}
                    </h2>
                    <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">
                        Foco: {profile.mainGoal?.replace('_', ' ').toUpperCase()}
                    </p>
                </div>
                <div className="w-14 h-14 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-full flex items-center justify-center text-xl font-black text-white shadow-lg shadow-blue-500/30">
                    {profile.name.charAt(0)}
                </div>
            </div>

            {todayWorkout ? (
                <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white shadow-2xl shadow-slate-900/20 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 group-hover:bg-blue-600/30 transition-colors" />
                    <div className="relative z-10">
                        <div className="flex justify-between items-start mb-8">
                            <span className="bg-white/10 backdrop-blur-md px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest border border-white/10">Treino de Hoje</span>
                            <Flame className="text-orange-500 animate-pulse" size={24} />
                        </div>

                        <h3 className="text-5xl font-black italic uppercase mb-2 leading-none tracking-tighter">{todayWorkout.type}</h3>
                        <p className="text-slate-400 font-medium line-clamp-2 mb-8">{todayWorkout.description || 'Siga a estrutura prescrita.'}</p>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-white/5 p-4 rounded-2xl border border-white/5">
                                <span className="text-[10px] uppercase text-slate-400 font-black tracking-wider block mb-1">Volume</span>
                                <span className="text-2xl font-black tracking-tight">
                                    {todayWorkout.distance ? `${todayWorkout.distance}km` : `${todayWorkout.totalTime}'`}
                                </span>
                            </div>
                            <div className="bg-white/5 p-4 rounded-2xl border border-white/5">
                                <span className="text-[10px] uppercase text-slate-400 font-black tracking-wider block mb-1">Intensidade</span>
                                <span className="text-2xl font-black tracking-tight">
