                             <span className="font-bold text-slate-800 text-lg">{workout.warmupTime} min</span>
                        </div>
                         <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Série</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.sets}x {workout.reps} ({workout.stimulusTime}/{workout.recoveryTime})</span>
                        </div>
                    </>
                 ) : isFartlek ? (
                     <>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Volume Total</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.totalTime} min</span>
                        </div>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Variação</span>
