                                <span className="text-[10px] uppercase text-slate-400 font-black tracking-wider block mb-1">Intensidade</span>
                                <span className="text-2xl font-black tracking-tight">
                                    {todayWorkout.pace || 'Mod'}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                 <div className="bg-slate-100 rounded-[2.5rem] p-10 text-center border-2 border-dashed border-slate-200">
                    <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm text-slate-300">
                        <HeartPulse size={32} />
                    </div>
                    <p className="text-slate-900 font-black text-xl italic uppercase tracking-tight">Descanso Total</p>
                    <p className="text-slate-400 text-sm font-medium mt-2">A recuperação faz parte do treino.</p>
                </div>
            )}

            <div className="space-y-4">
                <div className="flex items-center gap-2 mb-2">
                    <CalendarDays size={18} className="text-blue-600"/>
                    <h3 className="text-lg font-black italic uppercase text-slate-900 tracking-tighter">Agenda Semanal</h3>
                </div>
                {sortedWorkouts.map(w => (
                    <WorkoutCard key={w.id} workout={w} />
                ))}
            </div>

            <WorkoutLegend />
        </div>
    )
}

function WorkoutCard({ workout, onDelete }: { workout: WorkoutModel, onDelete?: () => void }) {
    const isInterval = workout.type === 'tiro' || workout.type === 'subida';
    const isFartlek = workout.type === 'fartlek';

    return (
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 relative group transition-all hover:shadow-xl hover:-translate-y-1">
            {onDelete && (
                <button onClick={onDelete} className="absolute top-6 right-6 text-slate-300 hover:text-rose-500 hover:bg-rose-50 p-2 rounded-xl transition-all">
                    <Trash2 size={20} />
                </button>
            )}

            <div className="flex flex-col mb-6">
                <span className="text-[10px] font-black uppercase tracking-widest text-blue-600 mb-1">
                    {workout.dayOfWeek}
                </span>
                <h4 className="text-3xl font-black italic uppercase text-slate-900 leading-none tracking-tighter">
                    {workout.type}
                </h4>
            </div>

            <div className="grid grid-cols-2 gap-6 mb-6">
                 {isInterval ? (
                    <>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Aquecimento</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.warmupTime} min</span>
                        </div>
                         <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Série</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.sets}x {workout.reps} ({workout.stimulusTime}/{workout.recoveryTime})</span>
                        </div>
                    </>
                 ) : isFartlek ? (
                     <>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Volume Total</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.totalTime} min</span>
                        </div>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Variação</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.fastTime}' Ft / {workout.slowTime}' Lv</span>
                        </div>
                     </>
                 ) : (
                    <>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Volume</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.distance ? `${workout.distance}km` : `${workout.totalTime}min`}</span>
                        </div>
                        <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Pace / Int</span>
                             <span className="font-bold text-slate-800 text-lg">{workout.pace || 'Livre'}</span>
                        </div>
                    </>
                 )}
            </div>

            {workout.description && (
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex gap-3">
                    <Info className="text-slate-400 shrink-0" size={16} />
                    <p className="text-xs text-slate-600 font-medium leading-relaxed">"{workout.description}"</p>
                </div>
            )}
        </div>
    )
}

function getDayIndex(day: string): number {
    const days = ['segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sábado', 'domingo'];
    const d = day.toLowerCase().split('-')[0];
    const idx = days.findIndex(x => x === d);
    return idx === -1 ? 99 : idx;
}

