type UserRole = 'professor' | 'student';

interface UserProfile {
  id: string;
  name: string;
  phone: string; 
  role: UserRole;
  anamnesisComplete: boolean;

  // BIOMETRIA & DADOS PESSOAIS
  birthDate?: string;
  gender?: string;
  weight?: string;
  height?: string;
  restingHeartRate?: string;
  maxHeartRate?: string;

  // ANAMNESE MÉDICA
  injuries?: string;
  medications?: string;
  surgery?: string;
  medicalClearance?: boolean;

  // HISTÓRICO ESPORTIVO
  runningYears?: string;
  weeklyVolume?: string; // km atuais
  recentPace?: string; // pace médio confortável
  best5k?: string;
  best10k?: string;

  // OBJETIVOS
  mainGoal?: string; // 'finish', 'time', 'distance', 'health'
  targetDistance?: string; // 5k, 10k, 21k, 42k
  availabilityDays?: string; // '3', '4', '5', '6'

  createdAt: string;
}

interface WorkoutModel {
  id: string;
  studentId: string;
  type: 'longao' | 'fartlek' | 'tiro' | 'ritmo' | 'subida' | 'regenerativo';
  dayOfWeek: string;

  // Dynamic fields
  warmupTime?: string;
  cooldownTime?: string;
  distance?: string; 
  totalTime?: string;
  pace?: string;

  // Intervals
  sets?: string;
  reps?: string;
  stimulusTime?: string;
  recoveryTime?: string;

  // Fartlek
  fastTime?: string;
  slowTime?: string;

  description?: string;
  color?: string;
}

const WorkoutCard: React.FC<{ workout: WorkoutModel, onDelete?: () => void }> = ({ workout, onDelete }) => {
    const isInterval = workout.type === 'tiro' || workout.type === 'subida';
    const isFartlek = workout.type === 'fartlek';

    return (
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 relative group transition-all hover:shadow-xl hover:-translate-y-1">
            {onDelete && (
                <button onClick={onDelete} className="absolute top-6 right-6 text-slate-300 hover:text-rose-500 hover:bg-rose-50 p-2 rounded-xl transition-all">
                    <Trash2 size={20} />
