// --- WIZARD DE AVALIAÇÃO (NOVO) ---

function AthleteAssessmentWizard({ onCancel, onComplete, onSaveLocal }: { onCancel: () => void, onComplete: (id: string) => void, onSaveLocal: (u: UserProfile) => void }) {
    const [step, setStep] = useState(1);
    const [loading, setLoading] = useState(false);
    const [calculatedAge, setCalculatedAge] = useState<number | null>(null);
    const [formData, setFormData] = useState<Partial<UserProfile>>({
        role: 'student',
        anamnesisComplete: true,
        gender: 'male',
        mainGoal: 'health',
        availabilityDays: '3',
        medicalClearance: true
    });

    // Auto-calculate Max Heart Rate when Birth Date or Gender changes
    useEffect(() => {
        if (formData.birthDate) {
            const birthDate = new Date(formData.birthDate);
            if (!isNaN(birthDate.getTime())) {
                const today = new Date();
                let age = today.getFullYear() - birthDate.getFullYear();
                const m = today.getMonth() - birthDate.getMonth();
                if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
                    age--;
                }
                setCalculatedAge(age);

                if (age > 0 && formData.gender) {
                    const calculatedMax = formData.gender === 'female' ? (226 - age) : (220 - age);
                    setFormData(prev => {
                        // Avoid infinite loop if value is already set to the calculated one
                        if (prev.maxHeartRate === calculatedMax.toString()) return prev;
                        return { ...prev, maxHeartRate: calculatedMax.toString() };
                    });
                }
            }
        }
    }, [formData.birthDate, formData.gender]);

    const updateData = (key: keyof UserProfile, value: any) => {
        setFormData(prev => ({ ...prev, [key]: value }));
    }

    const handleFinish = async () => {
        if (!formData.name || !formData.phone) {
            alert("Nome e Celular são obrigatórios para o cadastro.");
            return;
        }
        setLoading(true);

        // Robust Saving Mechanism: Try Firestore, fallback to Local
        try {
            // Race between 5s timeout and Firestore
            const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout')), 5000));
            const savePromise = addDoc(collection(db, 'artifacts', appId, 'users'), {
                ...formData,
                createdAt: new Date().toISOString()
            });

            const docRef = await Promise.race([savePromise, timeoutPromise]) as any;

            // Success
            onComplete(docRef.id);
        } catch (e) {
            console.warn("Firestore save failed or timed out, using local fallback:", e);
            // Fallback for offline/demo/error
            const localId = `local_${Date.now()}`;
            const studentData = {
                ...formData,
                id: localId,
                createdAt: new Date().toISOString()
            } as UserProfile;

            onSaveLocal(studentData);
            onComplete(localId);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 flex flex-col">
            <div className="h-2 w-full bg-slate-200">
                <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${(step/4)*100}%` }} />
            </div>

            <div className="flex-1 max-w-3xl mx-auto w-full p-6 flex flex-col justify-center">
                <div className="mb-8">
                    <button onClick={onCancel} className="text-slate-400 hover:text-slate-800 flex items-center gap-2 text-sm font-bold uppercase tracking-widest mb-4">
                        <X size={16} /> Cancelar Avaliação
                    </button>
                    <h2 className="text-4xl font-black italic uppercase text-slate-900 leading-none">
                        {step === 1 && "Dados Cadastrais"}
                        {step === 2 && "Avaliação Física"}
                        {step === 3 && "Anamnese & Saúde"}
                        {step === 4 && "Histórico & Objetivos"}
                    </h2>
                    <p className="text-slate-500 font-medium mt-2">Etapa {step} de 4: Vamos construir o perfil completo do atleta.</p>
                </div>

                <Card className="flex-1 max-h-[60vh] overflow-y-auto mb-8 shadow-xl border-blue-100">
                    {step === 1 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                            <Input label="Nome Completo" value={formData.name || ''} onChange={(v: string) => updateData('name', v)} placeholder="Nome do Atleta" />
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Celular (Login)" value={formData.phone || ''} onChange={(v: string) => updateData('phone', v)} placeholder="11999999999" type="tel" />
                                <Input label="Data de Nascimento" value={formData.birthDate || ''} onChange={(v: string) => updateData('birthDate', v)} type="date" />
                            </div>
                            {calculatedAge !== null && (
                                <p className="text-xs text-blue-600 font-bold bg-blue-50 p-2 rounded inline-block">
                                    Idade Calculada: {calculatedAge} Anos
                                </p>
                            )}
                            <Select label="Gênero Biológico" value={formData.gender} onChange={(v: string) => updateData('gender', v)} options={[
                                {value: 'male', label: 'Masculino'}, {value: 'female', label: 'Feminino'}
                            ]} />
                        </div>
                    )}

                    {step === 2 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Peso (kg)" type="number" value={formData.weight || ''} onChange={(v: string) => updateData('weight', v)} />
                                <Input label="Altura (cm)" type="number" value={formData.height || ''} onChange={(v: string) => updateData('height', v)} />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="FC Repouso (bpm)" type="number" value={formData.restingHeartRate || ''} onChange={(v: string) => updateData('restingHeartRate', v)} placeholder="Ex: 60" />
                                <div className="relative">
                                    <Input 
                                        label="FC Máxima (Estimada)" 
                                        type="number" 
                                        value={formData.maxHeartRate || ''} 
                                        onChange={(v: string) => updateData('maxHeartRate', v)} 
                                        placeholder="Calculando..."
                                        className="bg-blue-50/50 border-blue-200 text-blue-800"
                                    />
                                    <Sparkles className="absolute right-3 top-9 text-blue-400 pointer-events-none" size={16} />
                                </div>
                            </div>
                            <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 text-blue-800 text-sm">
                                <strong>Nota:</strong> A FC Máxima foi calculada automaticamente baseada na idade ({formData.gender === 'male' ? '220' : '226'} - {calculatedAge || 'idade'}), mas pode ser ajustada.
                            </div>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                            <TextArea label="Lesões Atuais ou Recentes" value={formData.injuries || ''} onChange={(v: string) => updateData('injuries', v)} placeholder="Descreva locais, dor e limitações..." />
                            <TextArea label="Medicamentos de Uso Contínuo" value={formData.medications || ''} onChange={(v: string) => updateData('medications', v)} placeholder="Nome e dosagem..." />
                            <TextArea label="Histórico Cirúrgico Relevante" value={formData.surgery || ''} onChange={(v: string) => updateData('surgery', v)} placeholder="Cirurgias ortopédicas ou cardíacas..." />
                             <Select label="Atestado Médico / Liberação" value={formData.medicalClearance ? 'yes' : 'no'} onChange={(v: string) => updateData('medicalClearance', v === 'yes')} options={[
                                {value: 'yes', label: 'Sim, apto para exercício vigoroso'}, {value: 'no', label: 'Não / Pendente'}
                            ]} />
                        </div>
                    )}

                    {step === 4 && (
                        <div className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                             <div className="grid grid-cols-2 gap-4">
                                <Input label="Anos de Corrida" type="number" value={formData.runningYears || ''} onChange={(v: string) => updateData('runningYears', v)} />
                                <Input label="Volume Semanal Atual (km)" type="number" value={formData.weeklyVolume || ''} onChange={(v: string) => updateData('weeklyVolume', v)} />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Melhor 5km (Min)" value={formData.best5k || ''} onChange={(v: string) => updateData('best5k', v)} placeholder="00:00" />
                                <Input label="Melhor 10km (Min)" value={formData.best10k || ''} onChange={(v: string) => updateData('best10k', v)} placeholder="00:00" />
                            </div>
                            <Select label="Objetivo Principal" value={formData.mainGoal} onChange={(v: string) => updateData('mainGoal', v)} options={[
                                {value: 'health', label: 'Saúde & Qualidade de Vida'},
                                {value: 'weight_loss', label: 'Emagrecimento'},
                                {value: 'performance_5k', label: 'Performance 5km'},
                                {value: 'performance_10k', label: 'Performance 10km'},
                                {value: 'half_marathon', label: 'Meia Maratona (21k)'},
                                {value: 'marathon', label: 'Maratona (42k)'}
                            ]} />
                            <Select label="Disponibilidade Semanal" value={formData.availabilityDays} onChange={(v: string) => updateData('availabilityDays', v)} options={[
                                {value: '2', label: '2 Dias (Manutenção)'},
                                {value: '3', label: '3 Dias (Mínimo Recomendado)'},
                                {value: '4', label: '4 Dias (Evolução)'},
                                {value: '5', label: '5 Dias (Performance)'},
                                {value: '6', label: '6 Dias (Alto Rendimento)'}
                            ]} />
                        </div>
                    )}
                </Card>

                <div className="flex justify-between items-center">
                    <Button variant="ghost" disabled={step === 1} onClick={() => setStep(s => s - 1)}>
                        <ChevronLeft /> Voltar
                    </Button>

                    {step < 4 ? (
                         <Button onClick={() => setStep(s => s + 1)}>
                            Próximo <ChevronRight />
                        </Button>
                    ) : (
                        <Button variant="success" loading={loading} onClick={handleFinish} className="px-8">
                            <Save size={18} /> Finalizar Cadastro
                        </Button>
                    )}
                </div>
            </div>
        </div>
    )
}

