function StudentLoginList({ students, onLogin, onBack }: { students: UserProfile[], onLogin: (p: UserProfile) => void, onBack: () => void }) {
    const [searchTerm, setSearchTerm] = useState("");
    const [selectedForAuth, setSelectedForAuth] = useState<UserProfile | null>(null);
    const [phoneInput, setPhoneInput] = useState("");
    const [error, setError] = useState("");

    const filtered = students.filter(s => s.name.toLowerCase().includes(searchTerm.toLowerCase()));

    const handleAuth = () => {
        if (!selectedForAuth) return;
        const storedPhone = selectedForAuth.phone.replace(/\D/g, '');
        const inputPhone = phoneInput.replace(/\D/g, '');

        if (storedPhone === inputPhone && inputPhone.length > 5) {
            onLogin(selectedForAuth);
        } else {
            setError("Número incorreto.");
        }
    }

    return (
        <div className="max-w-2xl mx-auto pt-10">
            <div className="flex items-center gap-4 mb-10">
                <button onClick={onBack} className="p-4 bg-brand-surface rounded-full border border-white/10 text-slate-400 hover:text-white transition-all hover:border-brand-neon/50">
                    <ArrowRight className="rotate-180" size={20} />
                </button>
                <h2 className="text-4xl font-black uppercase italic tracking-tighter text-white">Select Profile</h2>
            </div>

            <div className="relative mb-10 group">
                <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-brand-neon transition-colors" size={20} />
                <input 
                    type="text" 
                    placeholder="BUSCAR ATLETA..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-16 pr-6 py-6 rounded-[2rem] bg-brand-surface border border-slate-800 focus:border-brand-neon focus:ring-1 focus:ring-brand-neon outline-none font-black uppercase text-xl text-white placeholder:text-slate-700 transition-all"
                />
            </div>

            <div className="grid gap-3">
                {filtered.map(student => (
                    <div key={student.id} onClick={() => { setSelectedForAuth(student); setError(""); setPhoneInput(""); }} 
                        className="flex items-center justify-between p-5 bg-brand-light/30 border border-transparent hover:border-brand-neon/30 hover:bg-brand-light/50 rounded-2xl cursor-pointer transition-all group">
                        <div className="flex items-center gap-5">
                            <div className="w-12 h-12 bg-brand-dark rounded-xl flex items-center justify-center text-slate-500 font-black text-lg group-hover:text-brand-neon transition-colors border border-white/5">
                                {student.name.charAt(0)}
                            </div>
                            <div>
                                <h3 className="font-black text-lg text-white uppercase italic tracking-tight group-hover:translate-x-1 transition-transform">{student.name}</h3>
                                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Atleta</p>
                            </div>
                        </div>
                        <div className="w-10 h-10 rounded-full flex items-center justify-center text-slate-600 group-hover:text-brand-neon group-hover:translate-x-1 transition-all">
                            <ChevronRight size={24} />
                        </div>
                    </div>
                ))}
            </div>

            {selectedForAuth && (
                <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-6">
                    <Card className="max-w-md w-full animate-in zoom-in-95 duration-200 border-brand-neon/20 shadow-[0_0_50px_-10px_rgba(163,230,53,0.1)]">
                        <div className="flex justify-between items-start mb-8">
                            <div>
                                <h3 className="text-3xl font-black italic uppercase tracking-tighter text-white">Security</h3>
                                <p className="text-slate-400 text-xs mt-1 uppercase tracking-wider">Confirme seu número</p>
                            </div>
                            <button onClick={() => setSelectedForAuth(null)} className="text-slate-500 hover:text-white"><X /></button>
                        </div>
                        <div className="space-y-6">
                            <Input label="Celular Cadastrado" placeholder="11999999999" value={phoneInput} onChange={setPhoneInput} type="tel" className="bg-brand-dark" />
                            {error && <p className="text-red-500 text-xs font-bold flex items-center gap-2 uppercase tracking-wide"><AlertCircle size={14}/> {error}</p>}
                            <Button onClick={handleAuth} className="w-full py-5 text-sm">Acessar Painel</Button>
