                   workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek)).map(w => (
                       <WorkoutCard key={w.id} workout={w} onDelete={() => deleteWorkout(w.id)} />
                   )) 
                )}
            </div>

            <WorkoutLegend />
        </div>
    )
}

// --- WORKOUT BUILDER ---

function WorkoutBuilder({ student, onClose }: { student: UserProfile, onClose: () => void }) {
    const [type, setType] = useState<WorkoutModel['type']>('longao');
    const [day, setDay] = useState('Segunda');
    const [loading, setLoading] = useState(false);

    // Form States
    const [common, setCommon] = useState({ distance: '', time: '', pace: '', description: '', warmup: '10', cooldown: '5' });
    const [interval, setInterval] = useState({ sets: '1', reps: '10', stim: '2', rec: '1', recType: 'min' });
    const [fartlek, setFartlek] = useState({ fast: '1', slow: '1' });

    // Recommendation Engine
    const recommendation = useMemo(() => {
        let advice = { title: "General", volume: "Moderate", intensity: "Zone 2", notes: [] as string[] };
        if (type === 'longao') {
            advice.title = "Long Run";
            advice.intensity = "65-75% HRmax";
            advice.volume = "20-30% Weekly Vol";
        } else if (type === 'tiro') {
            advice.title = "Intervals";
            advice.intensity = "90-95% HRmax";
            advice.volume = "High Intensity";
            advice.notes.push("Mandatory 15min Warmup");
        }
        return advice;
    }, [type, student]);

    const handleSave = async () => {
        setLoading(true);
        try {
            const payload: any = {
                studentId: student.id,
                type,
                dayOfWeek: day,
                warmupTime: common.warmup,
                cooldownTime: common.cooldown,
                description: common.description,
                createdAt: new Date().toISOString()
            };

            let estimatedTotal = 0;
            const w = Number(common.warmup) || 0;
            const c = Number(common.cooldown) || 0;

            if (type === 'longao' || type === 'ritmo' || type === 'regenerativo') {
                payload.distance = common.distance;
                payload.pace = common.pace;
                payload.totalTime = common.time; 
            } else if (type === 'tiro' || type === 'subida') {
                payload.sets = interval.sets;
                payload.reps = interval.reps;
                payload.stimulusTime = interval.stim;
                payload.recoveryTime = interval.rec;
                estimatedTotal = w + c + ((Number(interval.sets)||1) * (Number(interval.reps)||1) * ((Number(interval.stim)||0) + (Number(interval.rec)||0)));
                payload.totalTime = String(estimatedTotal);
            } else if (type === 'fartlek') {
                payload.totalTime = common.time;
                payload.fastTime = fartlek.fast;
                payload.slowTime = fartlek.slow;
            }

            await addDoc(collection(db, 'artifacts', appId, 'workouts'), payload);
            onClose();
        } catch (e) { console.error(e); } finally { setLoading(false); }
    };

    return (
        <div className="flex flex-col lg:flex-row gap-6 animate-in zoom-in-95 duration-200">
            <div className="flex-1 bg-brand-light/20 border border-white/5 rounded-3xl p-6 relative">
                <button onClick={onClose} className="absolute top-6 right-6 text-slate-500 hover:text-white"><X /></button>
                <h4 className="text-xl font-black italic uppercase mb-8 text-brand-neon">New Session</h4>

                <div className="grid grid-cols-2 gap-4 mb-6">
                    <Select label="Dia" value={day} onChange={setDay} options={[
                        {value: 'Segunda', label: 'Segunda'}, {value: 'Terça', label: 'Terça'}, {value: 'Quarta', label: 'Quarta'},
                        {value: 'Quinta', label: 'Quinta'}, {value: 'Sexta', label: 'Sexta'}, {value: 'Sábado', label: 'Sábado'}, {value: 'Domingo', label: 'Domingo'}
                    ]} />
                    <Select label="Tipo" value={type} onChange={setType} options={[
                        {value: 'longao', label: 'Longão'}, {value: 'tiro', label: 'Intervalado'}, {value: 'fartlek', label: 'Fartlek'},
                        {value: 'ritmo', label: 'Tempo Run'}, {value: 'subida', label: 'Subida'}, {value: 'regenerativo', label: 'Regenerativo'}
                    ]} />
                </div>

                <div className="space-y-6 mb-8">
                    {(type === 'longao' || type === 'ritmo' || type === 'regenerativo') && (
                        <div className="grid grid-cols-2 gap-4">
                            <Input label="Km" type="number" value={common.distance} onChange={(v: string) => setCommon({...common, distance: v})} />
                            <Input label="Minutos" type="number" value={common.time} onChange={(v: string) => setCommon({...common, time: v})} />
                            <Input label="Pace (min/km)" value={common.pace} onChange={(v: string) => setCommon({...common, pace: v})} className="col-span-2" />
                        </div>
                    )}

                    {(type === 'tiro' || type === 'subida') && (
                        <div className="space-y-4">
                            <div className="grid grid-cols-3 gap-4">
                                <Input label="Warmup" type="number" value={common.warmup} onChange={(v: string) => setCommon({...common, warmup: v})} />
                                <Input label="Cooldown" type="number" value={common.cooldown} onChange={(v: string) => setCommon({...common, cooldown: v})} />
                                <Input label="Sets" type="number" value={interval.sets} onChange={(v: string) => setInterval({...interval, sets: v})} />
                            </div>
                            <div className="p-4 bg-brand-dark rounded-xl border border-white/5 grid grid-cols-3 gap-4">
                                <Input label="Reps" type="number" value={interval.reps} onChange={(v: string) => setInterval({...interval, reps: v})} />
                                <Input label="Stimulus" value={interval.stim} onChange={(v: string) => setInterval({...interval, stim: v})} />
                                <Input label="Recovery" value={interval.rec} onChange={(v: string) => setInterval({...interval, rec: v})} />
                            </div>
                        </div>
                    )}

                    {type === 'fartlek' && (
                        <div className="grid grid-cols-2 gap-4">
                             <Input label="Total Time" type="number" value={common.time} onChange={(v: string) => setCommon({...common, time: v})} className="col-span-2" />
                             <Input label="Fast" type="number" value={fartlek.fast} onChange={(v: string) => setFartlek({...fartlek, fast: v})} />
                             <Input label="Slow" type="number" value={fartlek.slow} onChange={(v: string) => setFartlek({...fartlek, slow: v})} />
                        </div>
                    )}

                    <TextArea label="Instructions" value={common.description} onChange={(v: string) => setCommon({...common, description: v})} placeholder="Ex: Keep posture, strong finish..." />
                </div>

                <Button onClick={handleSave} loading={loading} className="w-full">Create Workout</Button>
            </div>

             <div className="w-full lg:w-72">
                <div className="bg-brand-surface border border-white/5 p-6 rounded-3xl h-full">
                    <div className="flex items-center gap-2 mb-6 text-brand-neon">
                        <Brain size={18} /> <span className="text-xs font-black uppercase tracking-widest">AI Insight</span>
                    </div>
                    <h3 className="text-2xl font-black italic uppercase text-white mb-4">{recommendation.title}</h3>
                    <div className="space-y-4">
                         <div>
                            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-1">Target Intensity</span>
                            <p className="text-white font-bold">{recommendation.intensity}</p>
                        </div>
                        <div>
                            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-1">Volume Guide</span>
                            <p className="text-white font-bold">{recommendation.volume}</p>
                        </div>
                        {recommendation.notes.length > 0 && (
                            <div className="pt-4 border-t border-white/5">
                                <ul className="text-xs text-slate-400 space-y-2">
                                    {recommendation.notes.map((n, i) => <li key={i}>• {n}</li>)}
                                </ul>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

