export default function App() {
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [activeProfile, setActiveProfile] = useState<UserProfile | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<'login' | 'student-select' | 'dashboard' | 'new-athlete-assessment'>('login');

  // Data State
  const [dbStudents, setDbStudents] = useState<UserProfile[]>([]);
  const [localStudents, setLocalStudents] = useState<UserProfile[]>([]);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  // Combine DB and Local students
  const students = useMemo(() => {
    const dbIds = new Set(dbStudents.map(s => s.id));
    const uniqueLocal = localStudents.filter(s => !dbIds.has(s.id));
    return [...dbStudents, ...uniqueLocal];
  }, [dbStudents, localStudents]);

  useEffect(() => {
    if (app.options.apiKey === 'demo') {
      setCurrentUser({ uid: 'demo-user', isAnonymous: true });
      setLoading(false);
      return;
    }
    signInAnonymously(auth).catch((error) => {
      console.error("Auth failed:", error);
      setCurrentUser({ uid: 'fallback-user', isAnonymous: true });
      setLoading(false);
    });
    const unsubscribe = onAuthStateChanged(auth, (u) => {
      if (u) {
        setCurrentUser(u);
        setLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    try {
      const unsub = onSnapshot(collection(db, 'artifacts', appId, 'users'), (snap) => {
        const allUsers = snap.docs.map(d => ({ id: d.id, ...d.data() } as UserProfile));
        setDbStudents(allUsers.filter(u => u.role === 'student'));
      }, (error) => console.error(error));
      return () => unsub();
    } catch (e) {
      console.error(e);
    }
  }, []);

  // Login Handlers
  const loginAsProfessor = () => {
    setRole('professor');
    setView('dashboard');
  };

  const loginAsStudent = (profile: UserProfile) => {
    setActiveProfile(profile);
    setRole('student');
    setSelectedStudentId(profile.id);
    setView('dashboard');
  };

  if (loading) return <div className="h-screen w-full flex items-center justify-center bg-brand-dark"><div className="w-10 h-10 border-4 border-brand-neon border-t-transparent rounded-full animate-spin"></div></div>;

  return (
    <div className="min-h-screen bg-brand-dark text-white font-sans selection:bg-brand-neon selection:text-brand-dark">
      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none overflow-hidden">
        <div className="absolute top-[-20%] right-[-10%] w-[800px] h-[800px] bg-brand-neon/5 rounded-full blur-[120px]" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[600px] h-[600px] bg-blue-900/10 rounded-full blur-[100px]" />
      </div>

      {/* Header */}
      {view !== 'login' && view !== 'new-athlete-assessment' && (
        <header className="fixed top-0 left-0 right-0 h-20 glass-panel z-50 px-6 flex items-center justify-between border-b border-white/5">
            <div className="flex items-center gap-3">
                <div className="text-brand-neon">
                    <Activity size={24} strokeWidth={3} />
                </div>
                <div>
                    <h1 className="text-xl font-black italic uppercase tracking-tighter leading-none text-white">RUN<span className="text-brand-neon">TRACK</span></h1>
                    <p className="text-[9px] font-bold text-slate-500 uppercase tracking-[0.2em]">Elite Performance</p>
                </div>
            </div>

            <div className="flex items-center gap-4">
                {role === 'professor' && selectedStudentId && (
                   <div className="hidden md:flex items-center gap-2 px-4 py-2 bg-brand-light/50 rounded-full border border-white/10">
                      <UserCheck size={14} className="text-brand-neon"/>
                      <span className="text-xs font-bold text-slate-300 uppercase tracking-wider">{students.find(s => s.id === selectedStudentId)?.name}</span>
                   </div> 
                )}
                <button onClick={() => { setView('login'); setRole(null); setActiveProfile(null); setSelectedStudentId(null); }} className="p-2 hover:bg-white/10 rounded-full text-slate-400 hover:text-white transition-colors">
                    <LogOut size={20} />
                </button>
            </div>
        </header>
      )}

      {/* Main Content */}
      <main className={`relative z-10 transition-all duration-500 ${view !== 'login' && view !== 'new-athlete-assessment' ? 'pt-28 pb-12 px-6' : ''}`}>

        {view === 'login' && (
          <LoginScreen 
            onSelectProfessor={loginAsProfessor} 
            onSelectStudent={() => setView('student-select')} 
          />
        )}

        {view === 'student-select' && (
          <StudentLoginList 
            students={students} 
            onLogin={loginAsStudent} 
            onBack={() => setView('login')} 
          />
        )}

        {view === 'new-athlete-assessment' && role === 'professor' && (
            <AthleteAssessmentWizard 
                onCancel={() => setView('dashboard')}
                onSaveLocal={(student: UserProfile) => setLocalStudents(prev => [...prev, student])}
                onComplete={(newStudentId) => {
                    setSelectedStudentId(newStudentId);
                    setView('dashboard');
                }}
            />
        )}

        {view === 'dashboard' && role === 'professor' && (
            <ProfessorDashboard 
                students={students} 
                selectedStudentId={selectedStudentId}
                onSelectStudent={setSelectedStudentId}
                onNewStudent={() => setView('new-athlete-assessment')}
            />
        )}

        {view === 'dashboard' && role === 'student' && activeProfile && (
             <StudentView profile={activeProfile} />
        )}

      </main>
    </div>
  );
}

