function StudentView({ profile }: { profile: UserProfile }) {
    const [workouts, setWorkouts] = useState<WorkoutModel[]>([]);

    useEffect(() => {
        if (!profile.id) return;
        const q = collection(db, 'artifacts', appId, 'workouts');
        const unsub = onSnapshot(q, (snap) => {
            const data = snap.docs.map(d => ({id: d.id, ...d.data()} as WorkoutModel));
            setWorkouts(data.filter(w => w.studentId === profile.id));
        });
        return () => unsub();
    }, [profile.id]);

    const sortedWorkouts = workouts.sort((a,b) => getDayIndex(a.dayOfWeek) - getDayIndex(b.dayOfWeek));
    const daysMap = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];
    const todayName = daysMap[new Date().getDay()];
    const todayWorkout = workouts.find(w => w.dayOfWeek.includes(todayName.split('-')[0]));

    return (
        <div className="max-w-md mx-auto space-y-10 pb-24 animate-in fade-in duration-700">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-4xl font-black italic uppercase tracking-tighter text-white leading-none">
                        Hello,<br/>{profile.name.split(' ')[0]}
                    </h2>
                </div>
                <div className="w-16 h-16 bg-brand-neon text-brand-dark rounded-2xl flex items-center justify-center text-2xl font-black shadow-[0_0_20px_rgba(163,230,53,0.4)]">
                    {profile.name.charAt(0)}
                </div>
            </div>

            {/* HERO CARD */}
            {todayWorkout ? (
                <div className="relative overflow-hidden rounded-[2.5rem] bg-slate-900 border border-white/10 group">
                    <div className="absolute inset-0 bg-gradient-to-br from-brand-neon/20 to-transparent opacity-50 group-hover:opacity-100 transition-opacity" />
                    <div className="relative z-10 p-8">
                        <div className="flex justify-between items-start mb-12">
                            <span className="bg-brand-neon text-brand-dark px-3 py-1 rounded-md text-[10px] font-black uppercase tracking-widest">Today's Run</span>
                            <Play className="text-white fill-white" size={24} />
                        </div>

                        <h3 className="text-5xl font-black italic uppercase mb-2 leading-[0.85] tracking-tighter text-white">{todayWorkout.type}</h3>
                        <p className="text-slate-400 font-medium text-sm line-clamp-2 mb-8">{todayWorkout.description || 'Focus on your form.'}</p>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-black/40 backdrop-blur-md p-4 rounded-2xl border border-white/5">
                                <span className="text-[9px] uppercase text-slate-400 font-black tracking-wider block mb-1">Volume</span>
                                <span className="text-2xl font-black tracking-tight text-white">
                                    {todayWorkout.distance ? `${todayWorkout.distance}km` : `${todayWorkout.totalTime}'`}
                                </span>
                            </div>
                            <div className="bg-black/40 backdrop-blur-md p-4 rounded-2xl border border-white/5">
                                <span className="text-[9px] uppercase text-slate-400 font-black tracking-wider block mb-1">Intensity</span>
                                <span className="text-2xl font-black tracking-tight text-brand-neon">
                                    {todayWorkout.pace || 'Free'}
