                    {step < 4 ? (
                         <Button onClick={() => setStep(s => s + 1)} className="px-10">
                            PRÓXIMO <ChevronRight size={16}/>
                        </Button>
                    ) : (
                        <Button variant="primary" loading={loading} onClick={handleFinish} className="px-12 py-5 text-sm">
                            <Save size={18} /> FINALIZAR CADASTRO
                        </Button>
                    )}
                </div>
            </div>
        </div>
    )
}

