// --- TYPES ---
type UserRole = 'professor' | 'student';

interface UserProfile {
  id: string;
  name: string;
  phone: string; 
  role: UserRole;
  anamnesisComplete: boolean;
  birthDate?: string;
  gender?: string;
  weight?: string;
  height?: string;
  restingHeartRate?: string;
  maxHeartRate?: string;
  injuries?: string;
  medications?: string;
  surgery?: string;
  medicalClearance?: boolean;
  runningYears?: string;
  weeklyVolume?: string;
  recentPace?: string;
  best5k?: string;
  best10k?: string;
  mainGoal?: string;
  targetDistance?: string;
  availabilityDays?: string;
  createdAt: string;
}

interface WorkoutModel {
  id: string;
  studentId: string;
  type: 'longao' | 'fartlek' | 'tiro' | 'ritmo' | 'subida' | 'regenerativo';
  dayOfWeek: string;
  warmupTime?: string;
  cooldownTime?: string;
  distance?: string; 
  totalTime?: string;
  pace?: string;
  sets?: string;
  reps?: string;
  stimulusTime?: string;
  recoveryTime?: string;
  fastTime?: string;
  slowTime?: string;
  description?: string;
  color?: string;
}

