                            <span className="font-bold text-white text-2xl leading-none">
                                {workout.sets || '1'}x {workout.reps || '1'} 
                            </span>
                            <span className="text-sm font-bold text-brand-neon mb-1">
                                ({workout.stimulusTime || '--'} / {workout.recoveryTime || '--'})
                            </span>
                        </div>
                        {workout.speed && (
                             <span className="text-xs font-bold text-zinc-400 mt-2 border-t border-white/5 pt-2 flex items-center gap-1">
                                 <Zap size={10} className="text-brand-neon"/> @ {workout.speed} km/h
                             </span>
                        )}
                </div>
            </div>

            {workout.description && (
                <div className="p-4 rounded-xl border-l-2 border-brand-neon bg-brand-neon/5">
                    <p className="text-xs text-zinc-300 font-medium leading-relaxed italic">"{workout.description}"</p>
                </div>
            )}
        </div>
    )
}

